class _MultiScaleFactorResidual(nn.Module):
    """Zero-initialized factor-query pooling across ConvNeXt scales.

    The residual asks three task-specific queries, corresponding to friction,
    material, and roughness evidence, to read from several ConvNeXt stages.
    Image-derived physical evidence and global statistics condition both the
    query content and the factor-wise scale gate. The final projection is zero
    initialized, so inserting the block preserves the loaded backbone until the
    small residual is trained.
    """

    def __init__(
        self,
        *,
        out_dim: int,
        stage_channels: dict[int, int],
        token_dim: int = 128,
        residual_scale: float = 0.055,
        evidence_channels: int = 14,
        stats_dim: int = 28,
        pooled_size: int = 8,
        selective_gate: bool = False,
        selective_gate_bias: float = -2.2,
        selective_gate_floor: float = 0.0,
    ) -> None:
        super().__init__()
        self.stage_indices = tuple(sorted(int(k) for k in stage_channels))
        self.residual_scale = float(residual_scale)
        self.pooled_size = int(pooled_size)
        self.selective_gate = bool(selective_gate)
        self.selective_gate_bias = float(selective_gate_bias)
        self.selective_gate_floor = float(selective_gate_floor)
        token_dim = int(token_dim)
        self.stage_proj = nn.ModuleDict(
            {
                str(idx): nn.Sequential(
                    nn.Conv2d(int(stage_channels[idx]), token_dim, kernel_size=1, bias=False),
                    nn.GroupNorm(8, token_dim),
                    nn.GELU(),
                )
                for idx in self.stage_indices
            }
        )
        self.evidence_proj = nn.ModuleDict(
            {
                str(idx): nn.Sequential(
                    nn.Conv2d(int(evidence_channels), token_dim, kernel_size=1, bias=False),
                    nn.GroupNorm(8, token_dim),
                    nn.GELU(),
                )
                for idx in self.stage_indices
            }
        )
        self.key = nn.ModuleDict({str(idx): nn.Linear(token_dim, token_dim) for idx in self.stage_indices})
        self.value = nn.ModuleDict({str(idx): nn.Linear(token_dim, token_dim) for idx in self.stage_indices})
        self.factor_query = nn.Parameter(torch.empty(3, token_dim))
        self.stage_embedding = nn.Parameter(torch.empty(len(self.stage_indices), token_dim))
        self.stat_to_query = nn.Sequential(
            nn.LayerNorm(int(stats_dim)),
            nn.Linear(int(stats_dim), token_dim),
            nn.GELU(),
            nn.Linear(token_dim, 3 * token_dim),
        )
        self.scale_gate = nn.Sequential(
            nn.LayerNorm(int(stats_dim)),
            nn.Linear(int(stats_dim), token_dim),
            nn.GELU(),
            nn.Linear(token_dim, 3 * len(self.stage_indices)),
        )
        self.sample_gate = nn.Sequential(
            nn.LayerNorm(int(stats_dim)),
            nn.Linear(int(stats_dim), token_dim // 2),
            nn.GELU(),
            nn.Linear(token_dim // 2, 1),
        )
        residual_dim = 3 * token_dim + 3 * len(self.stage_indices) + 3 * len(self.stage_indices) + int(stats_dim)
        self.out = nn.Sequential(
            nn.LayerNorm(residual_dim),
            nn.Linear(residual_dim, int(out_dim)),
            nn.GELU(),
            nn.Dropout(0.10),
            nn.Linear(int(out_dim), int(out_dim)),
        )
        nn.init.trunc_normal_(self.factor_query, std=0.02)
        nn.init.trunc_normal_(self.stage_embedding, std=0.02)
        last = self.out[-1]
        if isinstance(last, nn.Linear):
            nn.init.zeros_(last.weight)
            nn.init.zeros_(last.bias)
        gate_last = self.sample_gate[-1]
        if isinstance(gate_last, nn.Linear):
            nn.init.zeros_(gate_last.weight)
            nn.init.zeros_(gate_last.bias)

    @staticmethod
    def _analytic_selective_prior(stats: torch.Tensor) -> torch.Tensor:
        """Open the residual mainly on RSCD hard regimes found by diagnosis.

        Boundary evidence stats are ordered as 14 means followed by 14 standard
        deviations. The prior is high when concrete/wet-film/visible roughness
        and macro texture variation co-occur, and is suppressed by marking-like
        artifacts. It is a soft gate, not a classifier.
        """

        means = stats[:, :14].float()
        stds = stats[:, 14:28].float()
        meso_std = stds[:, 4:5].clamp(0.0, 1.0)
        macro_std = stds[:, 5:6].clamp(0.0, 1.0)
        concrete = means[:, 6:7].clamp(0.0, 1.0)
        asphalt = means[:, 7:8].clamp(0.0, 1.0)
        specular = means[:, 8:9].clamp(0.0, 1.0)
        dark_water = means[:, 9:10].clamp(0.0, 1.0)
        film_erasure = means[:, 10:11].clamp(0.0, 1.0)
        visible_rough = means[:, 11:12].clamp(0.0, 1.0)
        marking = means[:, 13:14].clamp(0.0, 1.0)
        wet_film = torch.maximum(torch.maximum(specular, dark_water), film_erasure)
        concrete_wet_rough = concrete * torch.maximum(wet_film, visible_rough)
        asphalt_water_boundary = asphalt * wet_film * torch.sigmoid((0.060 - macro_std) * 18.0)
        dry_concrete_texture = concrete * torch.sigmoid((meso_std + macro_std - 0.035) * 18.0)
        rough_scale = torch.sigmoid((meso_std + macro_std + visible_rough - 0.065) * 16.0)
        artifact_guard = (1.0 - 0.65 * marking).clamp(0.10, 1.0)
        prior = (
            0.45 * concrete_wet_rough
            + 0.25 * asphalt_water_boundary
            + 0.25 * dry_concrete_texture
            + 0.05 * rough_scale
        ) * artifact_guard
        return prior.clamp(0.05, 1.0).to(dtype=stats.dtype)

    def forward(
        self,
        stage_maps: dict[int, torch.Tensor],
        evidence: torch.Tensor,
        stats: torch.Tensor,
    ) -> torch.Tensor:
        pooled_by_scale = []
        entropy_by_scale = []
        stats = stats.to(dtype=next(iter(stage_maps.values())).dtype)
        query_delta = self.stat_to_query(stats).view(stats.shape[0], 3, -1)
        for scale_idx, idx in enumerate(self.stage_indices):
            feat = stage_maps[idx]
            key = str(idx)
            token_map = self.stage_proj[key](feat)
            if token_map.shape[-2:] != (self.pooled_size, self.pooled_size):
                token_map = F.adaptive_avg_pool2d(token_map, (self.pooled_size, self.pooled_size))
            evidence_map = F.interpolate(evidence, size=token_map.shape[-2:], mode="bilinear", align_corners=False)
            token_map = token_map + self.evidence_proj[key](evidence_map.to(device=feat.device, dtype=token_map.dtype))
            tokens = token_map.flatten(2).transpose(1, 2)
            k = self.key[key](tokens)
            v = self.value[key](tokens)
            query = (
                self.factor_query.to(device=feat.device, dtype=token_map.dtype).unsqueeze(0)
                + self.stage_embedding[scale_idx].to(device=feat.device, dtype=token_map.dtype).view(1, 1, -1)
                + query_delta.to(device=feat.device, dtype=token_map.dtype)
            )
            attn = torch.softmax(torch.matmul(query, k.transpose(1, 2)) / math.sqrt(float(k.shape[-1])), dim=-1)
            pooled_by_scale.append(torch.matmul(attn, v))
            entropy_by_scale.append(
                -(attn * attn.clamp_min(1e-6).log()).sum(dim=-1) / math.log(float(attn.shape[-1]))
            )
        pooled = torch.stack(pooled_by_scale, dim=2)
        entropy = torch.stack(entropy_by_scale, dim=2)
        gates = self.scale_gate(stats).view(stats.shape[0], 3, len(self.stage_indices))
        gates = torch.softmax(gates, dim=2).to(dtype=pooled.dtype)
        fused = (pooled * gates.unsqueeze(-1)).sum(dim=2).flatten(1)
        residual_input = torch.cat([fused, gates.flatten(1), entropy.flatten(1), stats.to(dtype=pooled.dtype)], dim=1)
        residual = self.residual_scale * self.out(residual_input)
        if self.selective_gate:
            learned_gate = torch.sigmoid(self.sample_gate(stats).to(dtype=residual.dtype) + self.selective_gate_bias)
            analytic_gate = self._analytic_selective_prior(stats).to(dtype=residual.dtype)
            gate = learned_gate * analytic_gate
            floor = min(max(self.selective_gate_floor, 0.0), 1.0)
            if floor > 0.0:
                gate = floor + (1.0 - floor) * gate
            residual = residual * gate
        return residual


class ConvNeXtVisibilityCellularMultiScaleFactorBackbone(ConvNeXtVisibilityCellularTensorCouplingBackbone):
    """Visibility-cellular backbone with factor-wise multi-scale evidence pooling.

    This keeps the validated early full-order coupling bank and adds a separate
    zero-initialized residual after global pooling. The residual is not a late
    class head: it changes the backbone embedding by letting friction,
    material, and roughness queries select their own spatial scale.
    """

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        condition_layers: tuple[int, ...] = (0,),
        scale: float = 0.0020,
        max_update_ratio: float = 0.0015,
        artifact_suppression: float = 0.70,
        h_temperature: float = 10.0,
        h_margin: float = 0.014,
        active_cells: tuple[int, ...] | None = None,
        multiscale_residual_scale: float = 0.055,
        multiscale_selective_gate: bool = False,
        multiscale_selective_gate_bias: float = -2.2,
        multiscale_selective_gate_floor: float = 0.0,
    ) -> None:
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=condition_layers,
            scale=scale,
            max_update_ratio=max_update_ratio,
            artifact_suppression=artifact_suppression,
            h_temperature=h_temperature,
            h_margin=h_margin,
            active_cells=active_cells,
        )
        self.multiscale_factor_residual = _MultiScaleFactorResidual(
            out_dim=out_dim,
            stage_channels={3: 192, 5: 384, 7: 768},
            token_dim=128,
            residual_scale=multiscale_residual_scale,
            selective_gate=multiscale_selective_gate,
            selective_gate_bias=multiscale_selective_gate_bias,
            selective_gate_floor=multiscale_selective_gate_floor,
        )

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        feat = x
        stage_maps: dict[int, torch.Tensor] = {}
        named_stage_maps: dict[str, torch.Tensor] = {}
        for idx, layer in enumerate(self.features):
            feat = layer(feat)
            key = str(idx)
            if key in self.visibility_cellular_tensor_coupling_banks:
                feat = self.visibility_cellular_tensor_coupling_banks[key](feat, evidence, stats)
            if idx in {1, 3, 5, 7}:
                named_stage_maps[{1: "early", 3: "mid", 5: "late", 7: "final"}[idx]] = feat
            if idx in self.multiscale_factor_residual.stage_indices:
                stage_maps[idx] = feat
        self.stage_feature_maps = named_stage_maps
        self.last_feature_map = feat
        global_feat = self.avgpool(feat).flatten(1)
        return self.proj(global_feat) + self.multiscale_factor_residual(stage_maps, evidence, stats)


