class _FamilySplitPavedRoughnessOrdinalConditioner(_PavedRoughnessOrdinalConditioner):
    """Material-specific paved roughness conditioner.

    RSCD's slight/severe visual boundary is not shared by asphalt and concrete:
    asphalt roughness is dominated more by high-frequency texture and contrast,
    while concrete roughness is dominated more by block boundaries, cracks, and
    Laplacian-like discontinuities. This block reuses the zero-start early
    conditioner but narrows its support to one material family and gives that
    family a different roughness evidence mixture.
    """

    def __init__(self, channels: int, *, family: str, **kwargs) -> None:
        super().__init__(channels, **kwargs)
        if family not in {"asphalt", "concrete"}:
            raise ValueError(f"unsupported paved roughness family: {family}")
        self.family = family

    def _states(self, evidence: torch.Tensor, stats: torch.Tensor) -> tuple[torch.Tensor, torch.Tensor]:
        grad = evidence[:, 0:1].clamp(0.0, 1.5)
        lap = evidence[:, 1:2].clamp(0.0, 1.5)
        contrast = evidence[:, 2:3].clamp(0.0, 1.5)
        meso = evidence[:, 4:5].clamp(0.0, 1.5)
        macro = evidence[:, 5:6].clamp(0.0, 1.5)
        concrete = evidence[:, 6:7].clamp(0.0, 1.0)
        asphalt = evidence[:, 7:8].clamp(0.0, 1.0)
        specular = evidence[:, 8:9].clamp(0.0, 1.0)
        dark_water = evidence[:, 9:10].clamp(0.0, 1.0)
        erasure = evidence[:, 10:11].clamp(0.0, 1.0)
        visible_rough = evidence[:, 11:12].clamp(0.0, 1.0)
        boundary_or_winter = evidence[:, 12:13].clamp(0.0, 1.0)
        marking = evidence[:, 13:14].clamp(0.0, 1.0)

        film = torch.maximum(torch.maximum(specular, dark_water), erasure).clamp(0.0, 1.0)
        if self.family == "asphalt":
            target = asphalt
            other = concrete
            rough = (
                0.28 * visible_rough
                + 0.27 * grad
                + 0.15 * lap
                + 0.18 * contrast
                + 0.08 * meso
                + 0.04 * macro
            ).clamp(0.0, 1.0)
            wet_guard = (1.0 - 0.18 * film * torch.sigmoid((0.20 - rough) * self.gate_temperature)).clamp(0.25, 1.0)
        else:
            target = concrete
            other = asphalt
            rough = (
                0.34 * visible_rough
                + 0.15 * grad
                + 0.27 * lap
                + 0.08 * contrast
                + 0.06 * meso
                + 0.10 * macro
            ).clamp(0.0, 1.0)
            wet_guard = (1.0 - 0.10 * film * torch.sigmoid((0.18 - rough) * self.gate_temperature)).clamp(0.30, 1.0)

        temp = self.gate_temperature
        material_margin = (target - other).clamp(-1.0, 1.0)
        material_support = target * torch.sigmoid((material_margin + 0.04) * temp)
        rough_low = torch.sigmoid((0.24 - rough) * temp)
        rough_mid = torch.sigmoid((rough - 0.18) * temp) * torch.sigmoid((0.56 - rough) * temp)
        rough_high = torch.sigmoid((rough - 0.43) * temp)
        rough_boundary = torch.sigmoid((rough - 0.15) * temp) * torch.sigmoid((0.74 - rough) * temp)
        anti_marking = (1.0 - self.artifact_suppression * marking).clamp(0.12, 1.0)
        anti_winter_smooth = (1.0 - 0.40 * boundary_or_winter * rough_low).clamp(0.10, 1.0)

        support = (material_support * rough_boundary * anti_marking * anti_winter_smooth * wet_guard).clamp(0.0, 1.0)
        states = torch.cat([material_support.clamp(0.0, 1.0), film, rough_low, rough_mid, rough_high, anti_marking], dim=1)

        stats = stats.to(device=evidence.device, dtype=evidence.dtype)
        if self.family == "asphalt":
            stats_target = stats[:, 7:8].clamp(0.0, 1.0)
            stats_other = stats[:, 6:7].clamp(0.0, 1.0)
            stats_rough = (
                0.28 * stats[:, 11:12].clamp(0.0, 1.0)
                + 0.27 * stats[:, 0:1].clamp(0.0, 1.0)
                + 0.15 * stats[:, 1:2].clamp(0.0, 1.0)
                + 0.18 * stats[:, 2:3].clamp(0.0, 1.0)
                + 0.08 * stats[:, 4:5].clamp(0.0, 1.0)
                + 0.04 * stats[:, 5:6].clamp(0.0, 1.0)
            )
        else:
            stats_target = stats[:, 6:7].clamp(0.0, 1.0)
            stats_other = stats[:, 7:8].clamp(0.0, 1.0)
            stats_rough = (
                0.34 * stats[:, 11:12].clamp(0.0, 1.0)
                + 0.15 * stats[:, 0:1].clamp(0.0, 1.0)
                + 0.27 * stats[:, 1:2].clamp(0.0, 1.0)
                + 0.08 * stats[:, 2:3].clamp(0.0, 1.0)
                + 0.06 * stats[:, 4:5].clamp(0.0, 1.0)
                + 0.10 * stats[:, 5:6].clamp(0.0, 1.0)
            )
        stats_material = stats_target * torch.sigmoid(((stats_target - stats_other) + 0.04) * temp)
        stats_boundary = torch.sigmoid((stats_rough - 0.15) * temp) * torch.sigmoid((0.74 - stats_rough) * temp)
        stats_support = (stats_material * stats_boundary).view(-1, 1, 1, 1)
        support = (0.78 * support + 0.22 * stats_support).clamp(0.0, 1.0)
        return states, support


class ConvNeXtFamilySplitPavedRoughnessOrdinalBackbone(ConvNeXtGateCalibratedTensorCouplingBackbone):
    """S76-compatible anchor with separate asphalt/concrete roughness charts."""

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        roughness_layers: tuple[int, ...] = (0, 1),
        asphalt_scale: float = 0.010,
        concrete_scale: float = 0.012,
        roughness_max_update_ratio: float = 0.006,
    ) -> None:
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=(0,),
            scale=0.0010,
            max_update_ratio=0.00055,
            artifact_suppression=0.78,
            h_temperature=10.0,
            h_margin=0.016,
            gate_temperature=6.5,
            analytic_prior_weight=0.78,
            state_gate_scale=0.35,
            stats_gate_scale=0.25,
            mechanism_floor=0.040,
            counterfactual_strength=0.12,
            active_cells=(10, 11, 16, 17),
            up_init_std=2.0e-5,
        )
        stage_channels = {0: 96, 1: 96, 3: 192}
        self.asphalt_roughness_ordinal_conditioners = nn.ModuleDict(
            {
                str(idx): _FamilySplitPavedRoughnessOrdinalConditioner(
                    stage_channels[idx],
                    family="asphalt",
                    scale=asphalt_scale,
                    max_update_ratio=roughness_max_update_ratio,
                    gate_temperature=10.0,
                    artifact_suppression=0.80,
                )
                for idx in roughness_layers
                if idx in stage_channels
            }
        )
        self.concrete_roughness_ordinal_conditioners = nn.ModuleDict(
            {
                str(idx): _FamilySplitPavedRoughnessOrdinalConditioner(
                    stage_channels[idx],
                    family="concrete",
                    scale=concrete_scale,
                    max_update_ratio=roughness_max_update_ratio,
                    gate_temperature=10.0,
                    artifact_suppression=0.78,
                )
                for idx in roughness_layers
                if idx in stage_channels
            }
        )
        if not self.asphalt_roughness_ordinal_conditioners or not self.concrete_roughness_ordinal_conditioners:
            raise ValueError("ConvNeXtFamilySplitPavedRoughnessOrdinalBackbone needs valid roughness layers.")

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        feat = x
        for idx, layer in enumerate(self.features):
            feat = layer(feat)
            key = str(idx)
            if key in self.asphalt_roughness_ordinal_conditioners:
                feat = self.asphalt_roughness_ordinal_conditioners[key](feat, evidence, stats)
            if key in self.concrete_roughness_ordinal_conditioners:
                feat = self.concrete_roughness_ordinal_conditioners[key](feat, evidence, stats)
            if key in self.gate_calibrated_tensor_coupling_banks:
                feat = self.gate_calibrated_tensor_coupling_banks[key](feat, evidence, stats)
        self.last_feature_map = feat
        feat = self.avgpool(feat).flatten(1)
        return self.proj(feat)


class _SmoothProtectedRoughnessBoundaryConditioner(nn.Module):
    """Early RSCD roughness-boundary conditioner with smooth-cell protection.

    S100 showed that early mechanism conditioning can move the representation,
    but broad gates hurt high-confidence smooth cells. This conditioner writes
    only near paved smooth/slight/severe transition bands, uses different
    roughness mixtures for asphalt and concrete, and suppresses updates on
    obvious smooth, marking, and winter-like regions.
    """

    def __init__(
        self,
        channels: int,
        *,
        hidden_dim: int | None = None,
        scale: float = 0.016,
        max_update_ratio: float = 0.006,
        gate_temperature: float = 11.5,
        artifact_suppression: float = 0.80,
        init_std: float = 1.2e-5,
    ) -> None:
        super().__init__()
        channels = int(channels)
        hidden_dim = int(hidden_dim or max(64, min(160, channels)))
        self.scale = float(scale)
        self.max_update_ratio = max(float(max_update_ratio), 0.0)
        self.gate_temperature = max(float(gate_temperature), 1.0)
        self.artifact_suppression = min(max(float(artifact_suppression), 0.0), 0.95)

        groups = math.gcd(8, channels)
        self.norm = nn.GroupNorm(groups, channels)
        self.smooth_dw = nn.Conv2d(channels, channels, kernel_size=3, padding=1, groups=channels, bias=False)
        self.slight_dw = nn.Conv2d(channels, channels, kernel_size=5, padding=2, groups=channels, bias=False)
        self.severe_dw = nn.Conv2d(channels, channels, kernel_size=3, padding=2, dilation=2, groups=channels, bias=False)
        self.film_dw = nn.Conv2d(channels, channels, kernel_size=7, padding=3, groups=channels, bias=False)
        self.router = nn.Sequential(
            nn.Conv2d(channels + 9, hidden_dim, kernel_size=1, bias=False),
            nn.GELU(),
            nn.Conv2d(hidden_dim, 4, kernel_size=1),
        )
        self.update = nn.Sequential(
            nn.Conv2d(channels, channels, kernel_size=1),
            nn.GELU(),
            nn.Conv2d(channels, channels, kernel_size=1),
        )
        self.local_affine = nn.Conv2d(9, 2 * channels, kernel_size=1)
        self.global_affine = nn.Sequential(
            nn.LayerNorm(28),
            nn.Linear(28, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, 2 * channels),
        )
        last = self.update[-1]
        if isinstance(last, nn.Conv2d):
            if float(init_std) > 0.0:
                nn.init.normal_(last.weight, mean=0.0, std=float(init_std))
            else:
                nn.init.zeros_(last.weight)
            nn.init.zeros_(last.bias)
        nn.init.zeros_(self.local_affine.weight)
        nn.init.zeros_(self.local_affine.bias)
        global_last = self.global_affine[-1]
        if isinstance(global_last, nn.Linear):
            nn.init.zeros_(global_last.weight)
            nn.init.zeros_(global_last.bias)

    def _states(self, evidence: torch.Tensor, stats: torch.Tensor) -> tuple[torch.Tensor, torch.Tensor]:
        grad = evidence[:, 0:1].clamp(0.0, 1.5)
        lap = evidence[:, 1:2].clamp(0.0, 1.5)
        contrast = evidence[:, 2:3].clamp(0.0, 1.5)
        meso = evidence[:, 4:5].clamp(0.0, 1.5)
        macro = evidence[:, 5:6].clamp(0.0, 1.5)
        concrete = evidence[:, 6:7].clamp(0.0, 1.0)
        asphalt = evidence[:, 7:8].clamp(0.0, 1.0)
        specular = evidence[:, 8:9].clamp(0.0, 1.0)
        dark_water = evidence[:, 9:10].clamp(0.0, 1.0)
        erasure = evidence[:, 10:11].clamp(0.0, 1.0)
        visible_rough = evidence[:, 11:12].clamp(0.0, 1.0)
        boundary_or_winter = evidence[:, 12:13].clamp(0.0, 1.0)
        marking = evidence[:, 13:14].clamp(0.0, 1.0)

        film = torch.maximum(torch.maximum(specular, dark_water), erasure).clamp(0.0, 1.0)
        paved = torch.maximum(concrete, asphalt).clamp(0.0, 1.0)
        material_sum = (concrete + asphalt).clamp_min(1e-4)
        material_margin = (concrete - asphalt).abs().clamp(0.0, 1.0)
        asphalt_weight = asphalt / material_sum
        concrete_weight = concrete / material_sum

        rough_asphalt = (
            0.30 * visible_rough
            + 0.25 * grad
            + 0.14 * lap
            + 0.18 * contrast
            + 0.08 * meso
            + 0.05 * macro
        )
        rough_concrete = (
            0.32 * visible_rough
            + 0.14 * grad
            + 0.28 * lap
            + 0.08 * contrast
            + 0.07 * meso
            + 0.11 * macro
        )
        rough = (asphalt_weight * rough_asphalt + concrete_weight * rough_concrete).clamp(0.0, 1.0)

        temp = self.gate_temperature
        rough_low = torch.sigmoid((0.22 - rough) * temp)
        rough_mid = torch.sigmoid((rough - 0.14) * temp) * torch.sigmoid((0.53 - rough) * temp)
        rough_high = torch.sigmoid((rough - 0.42) * temp)
        rough_boundary = torch.sigmoid((rough - 0.10) * temp) * torch.sigmoid((0.66 - rough) * temp)
        smooth_conf = torch.sigmoid((0.13 - rough) * temp) * (1.0 - 0.35 * film).clamp(0.20, 1.0)
        smooth_protect = (1.0 - 0.88 * smooth_conf).clamp(0.08, 1.0)
        anti_marking = (1.0 - self.artifact_suppression * marking).clamp(0.12, 1.0)
        anti_winter_smooth = (1.0 - 0.42 * boundary_or_winter * rough_low).clamp(0.10, 1.0)
        film_boundary = film * torch.sigmoid((rough - 0.08) * temp) * torch.sigmoid((0.50 - rough) * temp)

        asphalt_support = asphalt * torch.sigmoid(((asphalt - concrete) + 0.03) * temp)
        concrete_support = concrete * torch.sigmoid(((concrete - asphalt) + 0.03) * temp)
        support = (
            paved
            * (0.42 + 0.58 * material_margin)
            * (0.68 * rough_boundary + 0.32 * film_boundary)
            * smooth_protect
            * anti_marking
            * anti_winter_smooth
        ).clamp(0.0, 1.0)

        states = torch.cat(
            [
                asphalt_support.clamp(0.0, 1.0),
                concrete_support.clamp(0.0, 1.0),
                film,
                rough_low,
                rough_mid,
                rough_high,
                smooth_protect,
                anti_marking,
                material_margin,
            ],
            dim=1,
        )

        stats = stats.to(device=evidence.device, dtype=evidence.dtype)
        stats_concrete = stats[:, 6:7].clamp(0.0, 1.0)
        stats_asphalt = stats[:, 7:8].clamp(0.0, 1.0)
        stats_sum = (stats_concrete + stats_asphalt).clamp_min(1e-4)
        stats_asphalt_weight = stats_asphalt / stats_sum
        stats_concrete_weight = stats_concrete / stats_sum
        stats_rough_asphalt = (
            0.30 * stats[:, 11:12].clamp(0.0, 1.0)
            + 0.25 * stats[:, 0:1].clamp(0.0, 1.0)
            + 0.14 * stats[:, 1:2].clamp(0.0, 1.0)
            + 0.18 * stats[:, 2:3].clamp(0.0, 1.0)
            + 0.08 * stats[:, 4:5].clamp(0.0, 1.0)
            + 0.05 * stats[:, 5:6].clamp(0.0, 1.0)
        )
        stats_rough_concrete = (
            0.32 * stats[:, 11:12].clamp(0.0, 1.0)
            + 0.14 * stats[:, 0:1].clamp(0.0, 1.0)
            + 0.28 * stats[:, 1:2].clamp(0.0, 1.0)
            + 0.08 * stats[:, 2:3].clamp(0.0, 1.0)
            + 0.07 * stats[:, 4:5].clamp(0.0, 1.0)
            + 0.11 * stats[:, 5:6].clamp(0.0, 1.0)
        )
        stats_rough = (
            stats_asphalt_weight * stats_rough_asphalt + stats_concrete_weight * stats_rough_concrete
        ).clamp(0.0, 1.0)
        stats_film = torch.maximum(torch.maximum(stats[:, 8:9], stats[:, 9:10]), stats[:, 10:11]).clamp(0.0, 1.0)
        stats_paved = torch.maximum(stats_concrete, stats_asphalt)
        stats_margin = (stats_concrete - stats_asphalt).abs().clamp(0.0, 1.0)
        stats_boundary = torch.sigmoid((stats_rough - 0.10) * temp) * torch.sigmoid((0.66 - stats_rough) * temp)
        stats_film_boundary = stats_film * torch.sigmoid((stats_rough - 0.08) * temp) * torch.sigmoid(
            (0.50 - stats_rough) * temp
        )
        stats_smooth_conf = torch.sigmoid((0.13 - stats_rough) * temp) * (1.0 - 0.35 * stats_film).clamp(0.20, 1.0)
        stats_smooth_protect = (1.0 - 0.88 * stats_smooth_conf).clamp(0.08, 1.0)
        stats_support = (
            stats_paved
            * (0.42 + 0.58 * stats_margin)
            * (0.68 * stats_boundary + 0.32 * stats_film_boundary)
            * stats_smooth_protect
        ).view(-1, 1, 1, 1)
        support = (0.78 * support + 0.22 * stats_support).clamp(0.0, 1.0)
        return states, support

    def forward(self, feat: torch.Tensor, evidence: torch.Tensor, stats: torch.Tensor) -> torch.Tensor:
        evidence = F.interpolate(evidence, size=feat.shape[-2:], mode="bilinear", align_corners=False)
        evidence = evidence.to(device=feat.device, dtype=feat.dtype)
        stats = stats.to(device=feat.device, dtype=feat.dtype)
        states, support = self._states(evidence, stats)

        z = self.norm(feat)
        low3 = F.avg_pool2d(z, kernel_size=3, stride=1, padding=1)
        low7 = F.avg_pool2d(z, kernel_size=7, stride=1, padding=3)
        low15 = F.avg_pool2d(z, kernel_size=15, stride=1, padding=7)
        micro = z - low3
        meso = low3 - low7
        macro = low7 - low15
        smooth = low15 - 0.12 * micro
        film_smooth = low15 - 0.24 * micro + 0.22 * macro
        branches = torch.stack(
            [
                self.smooth_dw(0.78 * smooth + 0.22 * meso),
                self.slight_dw(0.40 * micro + 0.60 * meso),
                self.severe_dw(0.25 * meso + 0.75 * macro),
                self.film_dw(0.62 * film_smooth + 0.38 * macro),
            ],
            dim=1,
        )
        route_prior = torch.cat(
            [
                states[:, 3:4] * states[:, 6:7],
                states[:, 4:5],
                states[:, 5:6],
                states[:, 2:3] * (0.40 + 0.60 * states[:, 4:5] + 0.35 * states[:, 5:6]).clamp(0.0, 1.0),
            ],
            dim=1,
        )
        route_logits = self.router(torch.cat([z, states], dim=1))
        route = torch.softmax(route_logits + 1.20 * route_prior, dim=1)
        mixed = (branches * route.unsqueeze(2)).sum(dim=1)

        local_gamma, local_beta = self.local_affine(states).chunk(2, dim=1)
        global_gamma, global_beta = self.global_affine(stats).view(feat.shape[0], -1, 1, 1).chunk(2, dim=1)
        delta = self.update(mixed)
        delta = delta + 0.05 * torch.tanh(local_gamma + global_gamma) * z
        delta = delta + 0.05 * torch.tanh(local_beta + global_beta)
        delta = support * delta
        if self.max_update_ratio > 0.0:
            delta_norm = delta.flatten(1).norm(dim=1).view(-1, 1, 1, 1).clamp_min(1e-6)
            feat_norm = feat.detach().flatten(1).norm(dim=1).view(-1, 1, 1, 1).clamp_min(1e-6)
            limit = self.max_update_ratio * feat_norm
            delta = delta * torch.minimum(torch.ones_like(delta_norm), limit / delta_norm)
        return feat + self.scale * delta


class ConvNeXtSmoothProtectedRoughnessBoundaryBackbone(ConvNeXtGateCalibratedTensorCouplingBackbone):
    """S96-compatible backbone with protected early roughness-boundary conditioning."""

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        boundary_layers: tuple[int, ...] = (0,),
        boundary_scale: float = 0.016,
        boundary_max_update_ratio: float = 0.006,
        boundary_init_std: float = 1.2e-5,
    ) -> None:
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=(0,),
            scale=0.0010,
            max_update_ratio=0.00055,
            artifact_suppression=0.78,
            h_temperature=10.0,
            h_margin=0.016,
            gate_temperature=6.5,
            analytic_prior_weight=0.78,
            state_gate_scale=0.35,
            stats_gate_scale=0.25,
            mechanism_floor=0.040,
            counterfactual_strength=0.12,
            active_cells=(10, 11, 16, 17),
            up_init_std=2.0e-5,
        )
        stage_channels = {0: 96, 1: 96, 3: 192}
        self.smooth_protected_roughness_boundary_conditioners = nn.ModuleDict(
            {
                str(idx): _SmoothProtectedRoughnessBoundaryConditioner(
                    stage_channels[idx],
                    scale=boundary_scale,
                    max_update_ratio=boundary_max_update_ratio,
                    gate_temperature=11.5,
                    artifact_suppression=0.80,
                    init_std=boundary_init_std,
                )
                for idx in boundary_layers
                if idx in stage_channels
            }
        )
        if not self.smooth_protected_roughness_boundary_conditioners:
            raise ValueError("ConvNeXtSmoothProtectedRoughnessBoundaryBackbone needs a valid boundary layer.")

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        feat = x
        for idx, layer in enumerate(self.features):
            feat = layer(feat)
            key = str(idx)
            if key in self.smooth_protected_roughness_boundary_conditioners:
                feat = self.smooth_protected_roughness_boundary_conditioners[key](feat, evidence, stats)
            if key in self.gate_calibrated_tensor_coupling_banks:
                feat = self.gate_calibrated_tensor_coupling_banks[key](feat, evidence, stats)
        self.last_feature_map = feat
        feat = self.avgpool(feat).flatten(1)
        return self.proj(feat)


class _FactorGraphTokenReadout(nn.Module):
    """RSCD factor-graph token readout over the final backbone feature map.

    The hard RSCD labels are not atomic visual classes: they combine friction,
    material, roughness, and non-additive couplings. This readout therefore
    pools final spatial features into factor and coupling tokens, performs a
    small fixed-topology graph message pass, and returns a bounded embedding
    residual before the classifier heads.
    """

    node_names = (
        "dry",
        "wet",
        "water",
        "asphalt",
        "concrete",
        "smooth",
        "slight",
        "severe",
        "fm",
        "fr",
        "mr",
        "fmr",
    )

    def __init__(
        self,
        channels: int,
        out_dim: int,
        *,
        token_dim: int = 128,
        hidden_dim: int = 192,
        stats_dim: int = 28,
        residual_scale: float = 0.055,
        residual_gate_floor: float = 0.18,
        artifact_suppression: float = 0.76,
        init_std: float = 1.2e-5,
    ) -> None:
        super().__init__()
        channels = int(channels)
        out_dim = int(out_dim)
        token_dim = int(token_dim)
        hidden_dim = int(hidden_dim)
        self.num_nodes = len(self.node_names)
        self.channels = channels
        self.token_dim = token_dim
        self.residual_scale = float(residual_scale)
        self.residual_gate_floor = min(max(float(residual_gate_floor), 0.0), 1.0)
        self.artifact_suppression = min(max(float(artifact_suppression), 0.0), 0.95)
        self.register_buffer("adjacency", self._build_adjacency())
        self.token_proj = nn.Sequential(
            nn.LayerNorm(channels),
            nn.Linear(channels, token_dim),
        )
        self.context = nn.Sequential(
            nn.LayerNorm(int(stats_dim) + self.num_nodes),
            nn.Linear(int(stats_dim) + self.num_nodes, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, self.num_nodes * token_dim),
        )
        self.message_q = nn.Linear(token_dim, token_dim, bias=False)
        self.message_k = nn.Linear(token_dim, token_dim, bias=False)
        self.message_v = nn.Linear(token_dim, token_dim, bias=False)
        self.message_proj = nn.Linear(token_dim, token_dim)
        self.node_gate = nn.Sequential(
            nn.LayerNorm(token_dim + int(stats_dim) + self.num_nodes),
            nn.Linear(token_dim + int(stats_dim) + self.num_nodes, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, 1),
        )
        self.out = nn.Sequential(
            nn.LayerNorm(self.num_nodes * token_dim),
            nn.Linear(self.num_nodes * token_dim, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, out_dim),
        )
        last = self.out[-1]
        if isinstance(last, nn.Linear):
            nn.init.normal_(last.weight, mean=0.0, std=float(init_std))
            nn.init.zeros_(last.bias)
        for module in (self.context[-1], self.message_proj, self.node_gate[-1]):
            if isinstance(module, nn.Linear):
                nn.init.zeros_(module.weight)
                nn.init.zeros_(module.bias)

    @classmethod
    def _build_adjacency(cls) -> torch.Tensor:
        n = len(cls.node_names)
        name_to_idx = {name: idx for idx, name in enumerate(cls.node_names)}
        adj = torch.eye(n, dtype=torch.float32)

        def connect(a: str, b: str, w: float = 1.0) -> None:
            ia, ib = name_to_idx[a], name_to_idx[b]
            adj[ia, ib] = max(float(adj[ia, ib]), float(w))
            adj[ib, ia] = max(float(adj[ib, ia]), float(w))

        for f in ("dry", "wet", "water"):
            connect(f, "fm", 0.85)
            connect(f, "fr", 0.85)
            connect(f, "fmr", 0.70)
        for m in ("asphalt", "concrete"):
            connect(m, "fm", 0.85)
            connect(m, "mr", 0.85)
            connect(m, "fmr", 0.70)
        for r in ("smooth", "slight", "severe"):
            connect(r, "fr", 0.85)
            connect(r, "mr", 0.85)
            connect(r, "fmr", 0.70)
        for a, b in (("smooth", "slight"), ("slight", "severe"), ("wet", "water"), ("asphalt", "concrete")):
            connect(a, b, 0.35)
        adj = adj / adj.sum(dim=1, keepdim=True).clamp_min(1e-6)
        return adj

    @staticmethod
    def _weighted_pool(feat: torch.Tensor, weight: torch.Tensor) -> torch.Tensor:
        weight = weight.to(device=feat.device, dtype=feat.dtype).clamp_min(1e-4)
        pooled = (feat * weight).sum(dim=(2, 3))
        denom = weight.sum(dim=(2, 3)).clamp_min(1e-4)
        return pooled / denom

    def _weights(self, evidence: torch.Tensor) -> tuple[torch.Tensor, torch.Tensor]:
        grad = evidence[:, 0:1].clamp(0.0, 1.5)
        lap = evidence[:, 1:2].clamp(0.0, 1.5)
        contrast = evidence[:, 2:3].clamp(0.0, 1.5)
        micro = evidence[:, 3:4].clamp(0.0, 1.5)
        meso = evidence[:, 4:5].clamp(0.0, 1.5)
        macro = evidence[:, 5:6].clamp(0.0, 1.5)
        concrete = evidence[:, 6:7].clamp(0.0, 1.0)
        asphalt = evidence[:, 7:8].clamp(0.0, 1.0)
        specular = evidence[:, 8:9].clamp(0.0, 1.0)
        dark_water = evidence[:, 9:10].clamp(0.0, 1.0)
        erasure = evidence[:, 10:11].clamp(0.0, 1.0)
        visible_rough = evidence[:, 11:12].clamp(0.0, 1.0)
        winter_or_boundary = evidence[:, 12:13].clamp(0.0, 1.0)
        marking = evidence[:, 13:14].clamp(0.0, 1.0)

        film = torch.maximum(torch.maximum(specular, dark_water), erasure).clamp(0.0, 1.0)
        rough = (
            0.32 * visible_rough
            + 0.20 * grad
            + 0.22 * lap
            + 0.12 * contrast
            + 0.08 * meso
            + 0.06 * macro
        ).clamp(0.0, 1.0)
        smooth = torch.sigmoid((0.23 - rough) * 10.5)
        slight = torch.sigmoid((rough - 0.16) * 10.0) * torch.sigmoid((0.55 - rough) * 10.0)
        severe = torch.sigmoid((rough - 0.43) * 10.0)
        paved = torch.maximum(asphalt, concrete).clamp(0.0, 1.0)
        clean = (1.0 - self.artifact_suppression * marking).clamp(0.12, 1.0)
        nonwinter = (1.0 - 0.42 * winter_or_boundary * smooth).clamp(0.16, 1.0)
        dry = ((1.0 - film).clamp(0.0, 1.0) * paved * clean * nonwinter).clamp(0.0, 1.0)
        wet = (torch.maximum(specular, erasure) * paved * clean).clamp(0.0, 1.0)
        water = (torch.maximum(dark_water, 0.75 * erasure) * paved * clean).clamp(0.0, 1.0)
        asphalt = (asphalt * clean).clamp(0.0, 1.0)
        concrete = (concrete * clean).clamp(0.0, 1.0)
        smooth = (smooth * paved * clean).clamp(0.0, 1.0)
        slight = (slight * paved * clean).clamp(0.0, 1.0)
        severe = (severe * paved * clean).clamp(0.0, 1.0)

        friction = torch.maximum(dry, torch.maximum(wet, water))
        material = torch.maximum(asphalt, concrete)
        roughness = torch.maximum(smooth, torch.maximum(slight, severe))
        fm = (friction * material).clamp(0.0, 1.0)
        fr = (friction * roughness).clamp(0.0, 1.0)
        mr = (material * roughness).clamp(0.0, 1.0)
        fmr = (
            0.34 * torch.maximum(wet, water) * material * torch.maximum(slight, severe)
            + 0.28 * water * concrete * torch.maximum(smooth, slight)
            + 0.22 * wet * concrete * torch.maximum(slight, severe)
            + 0.16 * dry * concrete * torch.maximum(slight, severe)
        ).clamp(0.0, 1.0)
        weights = torch.cat([dry, wet, water, asphalt, concrete, smooth, slight, severe, fm, fr, mr, fmr], dim=1)
        node_stats = weights.mean(dim=(2, 3))
        return weights.clamp_min(1e-4), node_stats

    def forward(self, feat: torch.Tensor, evidence: torch.Tensor, stats: torch.Tensor) -> tuple[torch.Tensor, dict[str, torch.Tensor]]:
        evidence = F.interpolate(evidence, size=feat.shape[-2:], mode="bilinear", align_corners=False)
        evidence = evidence.to(device=feat.device, dtype=feat.dtype)
        stats = stats.to(device=feat.device, dtype=feat.dtype)
        weights, node_stats = self._weights(evidence)
        pooled = torch.stack([self._weighted_pool(feat, weights[:, idx : idx + 1]) for idx in range(self.num_nodes)], dim=1)
        tokens = self.token_proj(pooled)
        context = torch.cat([stats, node_stats], dim=1)
        tokens = tokens + 0.20 * torch.tanh(self.context(context).view(feat.shape[0], self.num_nodes, self.token_dim))

        norm_tokens = F.layer_norm(tokens, (self.token_dim,))
        q = self.message_q(norm_tokens)
        k = self.message_k(norm_tokens)
        v = self.message_v(norm_tokens)
        logits = torch.matmul(q, k.transpose(1, 2)) / math.sqrt(float(self.token_dim))
        graph_prior = self.adjacency.to(device=feat.device, dtype=feat.dtype).clamp_min(1e-4).log().unsqueeze(0)
        attn = torch.softmax(logits + 1.35 * graph_prior, dim=-1)
        graph_msg = torch.matmul(attn, v)
        tokens = tokens + 0.32 * self.message_proj(graph_msg)

        gate_context = context.unsqueeze(1).expand(-1, self.num_nodes, -1)
        node_gate = torch.sigmoid(self.node_gate(torch.cat([tokens, gate_context], dim=2)))
        gated_tokens = tokens * (0.45 + 0.55 * node_gate)
        hard_support = node_stats[:, 8:].max(dim=1, keepdim=True).values
        residual_gate = self.residual_gate_floor + (1.0 - self.residual_gate_floor) * hard_support
        delta = self.residual_scale * residual_gate * torch.tanh(self.out(gated_tokens.flatten(1)))
        return delta, {
            "node_stats": node_stats,
            "node_gate": node_gate.squeeze(-1),
            "residual_gate": residual_gate,
        }


class ConvNeXtFactorGraphTokenReadoutBackbone(ConvNeXtGateCalibratedTensorCouplingBackbone):
    """S96 backbone with an RSCD factor-graph final token readout."""

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        readout_scale: float = 0.055,
        readout_gate_floor: float = 0.18,
        readout_init_std: float = 1.2e-5,
    ) -> None:
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=(0,),
            scale=0.0010,
            max_update_ratio=0.00055,
            artifact_suppression=0.78,
            h_temperature=10.0,
            h_margin=0.016,
            gate_temperature=6.5,
            analytic_prior_weight=0.78,
            state_gate_scale=0.35,
            stats_gate_scale=0.25,
            mechanism_floor=0.040,
            counterfactual_strength=0.12,
            active_cells=(10, 11, 16, 17),
            up_init_std=2.0e-5,
        )
        self.factor_graph_token_readout = _FactorGraphTokenReadout(
            self.proj.in_features,
            out_dim,
            residual_scale=readout_scale,
            residual_gate_floor=readout_gate_floor,
            artifact_suppression=0.76,
            init_std=readout_init_std,
        )
        self.last_factor_graph_readout: dict[str, torch.Tensor] = {}

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        feat = x
        for idx, layer in enumerate(self.features):
            feat = layer(feat)
            key = str(idx)
            if key in self.gate_calibrated_tensor_coupling_banks:
                feat = self.gate_calibrated_tensor_coupling_banks[key](feat, evidence, stats)
        self.last_feature_map = feat
        global_feat = self.avgpool(feat).flatten(1)
        delta, aux = self.factor_graph_token_readout(feat, evidence, stats)
        self.last_factor_graph_readout = {name: value.detach() for name, value in aux.items()}
        return self.proj(global_feat) + delta


class ConvNeXtRecursiveStateGateCalibratedBackbone(ConvNeXtGateCalibratedTensorCouplingBackbone):
    """S96 tensor-coupling backbone with recursive RSCD factor-state routing.

    Unlike the earlier standalone recursive backbone, this keeps the validated
    S96 gate-calibrated tensor bank and adds a small stateful mechanism route.
    The soft factor state is updated stage by stage and controls which local
    physical mechanism is allowed to write into the feature map.
    """

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        recursive_scale_multiplier: float = 0.85,
        recursive_early_scale_multiplier: float = 1.0,
        recursive_max_update_multiplier: float = 0.85,
        recursive_up_init_std: float = 1.2e-5,
    ) -> None:
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=(0,),
            scale=0.0010,
            max_update_ratio=0.00055,
            artifact_suppression=0.78,
            h_temperature=10.0,
            h_margin=0.016,
            gate_temperature=6.5,
            analytic_prior_weight=0.78,
            state_gate_scale=0.35,
            stats_gate_scale=0.25,
            mechanism_floor=0.040,
            counterfactual_strength=0.12,
            active_cells=(10, 11, 16, 17),
            up_init_std=2.0e-5,
        )
        stage_channels = {0: 96, 1: 96, 3: 192}
        specs = {
            0: ("visible_material", "visible_roughness"),
            1: ("thin_film", "water_obstruction", "granular_boundary"),
            3: ("hidden_roughness", "thin_film", "visible_roughness"),
        }
        scales = {0: 0.00085, 1: 0.00076, 3: 0.00060}
        max_updates = {0: 0.00046, 1: 0.00042, 3: 0.00035}
        self.recursive_state_banks = nn.ModuleDict(
            {
                str(idx): _RecursiveMechanismRoutingBank(
                    stage_channels[idx],
                    active_mechanisms=tuple(mechanisms),
                    scale=float(scales[idx])
                    * float(recursive_scale_multiplier)
                    * (float(recursive_early_scale_multiplier) if idx in {0, 1} else 1.0),
                    max_update_ratio=float(max_updates[idx])
                    * float(recursive_max_update_multiplier)
                    * (float(recursive_early_scale_multiplier) if idx in {0, 1} else 1.0),
                    artifact_suppression=0.78,
                    up_init_std=float(recursive_up_init_std),
                )
                for idx, mechanisms in specs.items()
            }
        )
        self.last_factor_state: torch.Tensor | None = None

    @staticmethod
    def _normalize_groups(state: torch.Tensor) -> torch.Tensor:
        friction = state[:, 0:3] / state[:, 0:3].sum(dim=1, keepdim=True).clamp_min(1e-5)
        material = state[:, 3:5] / state[:, 3:5].sum(dim=1, keepdim=True).clamp_min(1e-5)
        roughness = state[:, 5:8] / state[:, 5:8].sum(dim=1, keepdim=True).clamp_min(1e-5)
        return torch.cat([friction, material, roughness], dim=1)

    def _initial_factor_state(self, evidence: torch.Tensor) -> torch.Tensor:
        grad = evidence[:, 0:1].clamp(0.0, 1.5)
        lap = evidence[:, 1:2].clamp(0.0, 1.5)
        contrast = evidence[:, 2:3].clamp(0.0, 1.5)
        meso = evidence[:, 4:5].clamp(0.0, 1.5)
        macro = evidence[:, 5:6].clamp(0.0, 1.5)
        concrete = evidence[:, 6:7].clamp(0.0, 1.0)
        asphalt = evidence[:, 7:8].clamp(0.0, 1.0)
        specular = evidence[:, 8:9].clamp(0.0, 1.0)
        dark_water = evidence[:, 9:10].clamp(0.0, 1.0)
        film_erasure = evidence[:, 10:11].clamp(0.0, 1.0)
        visible_roughness = evidence[:, 11:12].clamp(0.0, 1.0)
        marking = evidence[:, 13:14].clamp(0.0, 1.0)
        clean = (1.0 - 0.72 * marking).clamp(0.12, 1.0)
        film = torch.maximum(specular, film_erasure).clamp(0.0, 1.0)
        water = (0.74 * dark_water + 0.26 * film_erasure).clamp(0.0, 1.0)
        paved = torch.maximum(asphalt, concrete).clamp(0.0, 1.0)
        rough = (0.42 * visible_roughness + 0.20 * grad + 0.18 * lap + 0.12 * meso + 0.08 * macro).clamp(
            0.0,
            1.0,
        )
        smooth = torch.sigmoid((0.34 - rough) * 9.0)
        severe = torch.sigmoid((rough - 0.56) * 9.0)
        slight = (rough * (1.0 - 0.58 * severe) * (1.0 - 0.28 * smooth)).clamp(0.0, 1.0)
        state_maps = torch.cat(
            [
                clean * paved * (1.0 - torch.maximum(film, water)).clamp(0.0, 1.0) + 0.05,
                clean * film * paved * (1.0 - 0.50 * water).clamp(0.0, 1.0) + 0.05,
                clean * water * paved + 0.05,
                clean * asphalt + 0.05,
                clean * concrete + 0.05,
                clean * smooth + 0.05,
                clean * slight + 0.05,
                clean * severe + 0.05,
            ],
            dim=1,
        )
        state = state_maps.mean(dim=(2, 3))
        texture_uncertainty = torch.sigmoid((0.12 - (grad + contrast).mean(dim=(2, 3))) * 8.0)
        rough_uniform = torch.full_like(state[:, 5:8], 1.0 / 3.0)
        state = self._normalize_groups(state)
        state = torch.cat(
            [
                state[:, 0:5],
                (1.0 - 0.22 * texture_uncertainty) * state[:, 5:8] + 0.22 * texture_uncertainty * rough_uniform,
            ],
            dim=1,
        )
        return self._normalize_groups(state)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        state = self._initial_factor_state(evidence).to(device=x.device, dtype=x.dtype)
        feat = x
        for idx, layer in enumerate(self.features):
            feat = layer(feat)
            key = str(idx)
            if key in self.recursive_state_banks:
                feat, state = self.recursive_state_banks[key](feat, evidence, stats, state)
            if key in self.gate_calibrated_tensor_coupling_banks:
                feat = self.gate_calibrated_tensor_coupling_banks[key](feat, evidence, stats)
        self.last_factor_state = state.detach()
        self.last_feature_map = feat
        feat = self.avgpool(feat).flatten(1)
        return self.proj(feat)


class _ContactRegionTokenConditioner(nn.Module):
    """Contact-evidence token conditioner for RSCD patch classification.

    Unlike a generic attention block, the tokens here are tied to RSCD's road
    mechanisms: clean contact, film, rough contact, asphalt texture, concrete
    discontinuity, smooth-wet ambiguity, severe roughness, and nuisance evidence.
    The block is orientation agnostic because RSCD patches may be cropped from
    turns or non-forward views; it uses local physical evidence instead of a
    fixed bottom-of-image ROI.
    """

    def __init__(
        self,
        channels: int,
        *,
        token_dim: int | None = None,
        hidden_dim: int | None = None,
        num_heads: int = 4,
        scale: float = 0.030,
        max_update_ratio: float = 0.012,
        evidence_channels: int = 14,
        stats_dim: int = 28,
        artifact_suppression: float = 0.72,
        target_family: str = "all",
        strict_support: bool = False,
    ) -> None:
        super().__init__()
        channels = int(channels)
        if target_family not in {"all", "concrete"}:
            raise ValueError(f"unsupported contact token target family: {target_family}")
        token_dim = int(token_dim or max(64, min(128, channels)))
        num_heads = int(num_heads)
        if token_dim % num_heads != 0:
            num_heads = math.gcd(token_dim, num_heads)
        hidden_dim = int(hidden_dim or max(64, min(192, channels)))
        self.channels = channels
        self.token_dim = token_dim
        self.num_heads = max(num_heads, 1)
        self.head_dim = token_dim // self.num_heads
        self.num_tokens = 8
        self.scale = float(scale)
        self.max_update_ratio = max(float(max_update_ratio), 0.0)
        self.evidence_channels = int(evidence_channels)
        self.stats_dim = int(stats_dim)
        self.artifact_suppression = min(max(float(artifact_suppression), 0.0), 0.95)
        self.target_family = target_family
        self.strict_support = bool(strict_support)

        self.norm = nn.GroupNorm(math.gcd(8, channels), channels)
        self.token_seed = nn.Parameter(torch.randn(self.num_tokens, token_dim) * 0.018)
        self.token_context = nn.Sequential(
            nn.LayerNorm(self.stats_dim + self.evidence_channels + self.num_tokens),
            nn.Linear(self.stats_dim + self.evidence_channels + self.num_tokens, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, self.num_tokens * token_dim),
        )
        self.key = nn.Conv2d(channels, token_dim, kernel_size=1, bias=False)
        self.value = nn.Conv2d(channels, token_dim, kernel_size=1, bias=False)
        self.token_q = nn.Linear(token_dim, token_dim, bias=False)
        self.token_k = nn.Linear(token_dim, token_dim, bias=False)
        self.token_v = nn.Linear(token_dim, token_dim, bias=False)
        self.token_proj = nn.Linear(token_dim, token_dim)
        self.spatial_proj = nn.Conv2d(token_dim, channels, kernel_size=1, bias=False)
        self.local_gate = nn.Sequential(
            nn.Conv2d(channels + self.num_tokens, hidden_dim, kernel_size=1, bias=False),
            nn.GELU(),
            nn.Conv2d(hidden_dim, 1, kernel_size=1),
        )
        self.update = nn.Sequential(
            nn.Conv2d(2 * channels, channels, kernel_size=1, bias=False),
            nn.GroupNorm(math.gcd(8, channels), channels),
            nn.GELU(),
            nn.Conv2d(channels, channels, kernel_size=1),
        )
        for module in (self.token_context[-1], self.token_proj, self.local_gate[-1]):
            if isinstance(module, (nn.Linear, nn.Conv2d)):
                nn.init.zeros_(module.weight)
                nn.init.zeros_(module.bias)
        last = self.update[-1]
        if isinstance(last, nn.Conv2d):
            nn.init.trunc_normal_(last.weight, std=1.0e-5)
            nn.init.zeros_(last.bias)

    @staticmethod
    def _clamp01(x: torch.Tensor) -> torch.Tensor:
        return x.clamp(0.0, 1.0)

    def _token_priors(self, evidence: torch.Tensor) -> torch.Tensor:
        grad = evidence[:, 0:1].clamp(0.0, 1.5)
        lap = evidence[:, 1:2].clamp(0.0, 1.5)
        contrast = evidence[:, 2:3].clamp(0.0, 1.5)
        meso = evidence[:, 4:5].clamp(0.0, 1.5)
        macro = evidence[:, 5:6].clamp(0.0, 1.5)
        concrete = self._clamp01(evidence[:, 6:7])
        asphalt = self._clamp01(evidence[:, 7:8])
        specular = self._clamp01(evidence[:, 8:9])
        dark_water = self._clamp01(evidence[:, 9:10])
        erasure = self._clamp01(evidence[:, 10:11])
        visible_rough = self._clamp01(evidence[:, 11:12])
        boundary_or_winter = self._clamp01(evidence[:, 12:13])
        marking = self._clamp01(evidence[:, 13:14])

        material = concrete if self.target_family == "concrete" else torch.maximum(concrete, asphalt)
        film = torch.maximum(torch.maximum(specular, dark_water), erasure)
        anti_mark = (1.0 - self.artifact_suppression * marking).clamp(0.10, 1.0)
        anti_nuisance = (1.0 - 0.38 * boundary_or_winter).clamp(0.18, 1.0)
        rough = (0.34 * visible_rough + 0.20 * grad + 0.22 * lap + 0.10 * contrast + 0.06 * meso + 0.08 * macro).clamp(0.0, 1.0)
        severe = torch.sigmoid((rough - 0.42) * 10.0)
        smooth = torch.sigmoid((0.24 - rough) * 10.0)

        clean_contact = (material * anti_mark * anti_nuisance * (1.0 - 0.18 * film)).clamp(0.0, 1.0)
        film_contact = (material * film * anti_mark).clamp(0.0, 1.0)
        rough_contact = (material * rough * anti_mark * anti_nuisance).clamp(0.0, 1.0)
        if self.target_family == "concrete":
            asphalt_texture = (asphalt * anti_mark).clamp(0.0, 1.0)
        else:
            asphalt_texture = (asphalt * (0.38 * grad + 0.26 * contrast + 0.24 * visible_rough + 0.12 * meso) * anti_mark).clamp(0.0, 1.0)
        concrete_break = (concrete * (0.34 * lap + 0.22 * visible_rough + 0.18 * grad + 0.16 * macro + 0.10 * meso) * anti_mark).clamp(0.0, 1.0)
        smooth_wet = (material * film * smooth * anti_mark).clamp(0.0, 1.0)
        severe_rough = (material * severe * anti_mark * anti_nuisance).clamp(0.0, 1.0)
        nuisance = torch.maximum(marking, boundary_or_winter).clamp(0.0, 1.0)
        return torch.cat(
            [
                clean_contact,
                film_contact,
                rough_contact,
                asphalt_texture,
                concrete_break,
                smooth_wet,
                severe_rough,
                nuisance,
            ],
            dim=1,
        )

    def _to_heads(self, x: torch.Tensor) -> torch.Tensor:
        if x.dim() == 3:
            bsz, length, _ = x.shape
            return x.view(bsz, length, self.num_heads, self.head_dim).transpose(1, 2)
        bsz, _, height, width = x.shape
        return x.flatten(2).transpose(1, 2).view(bsz, height * width, self.num_heads, self.head_dim).transpose(1, 2)

    def _from_heads(self, x: torch.Tensor, *, height: int | None = None, width: int | None = None) -> torch.Tensor:
        bsz = x.shape[0]
        x = x.transpose(1, 2).contiguous().view(bsz, x.shape[2], self.token_dim)
        if height is not None and width is not None:
            return x.transpose(1, 2).contiguous().view(bsz, self.token_dim, height, width)
        return x

    def forward(self, feat: torch.Tensor, evidence: torch.Tensor, stats: torch.Tensor) -> torch.Tensor:
        height, width = feat.shape[-2:]
        evidence = F.interpolate(evidence, size=(height, width), mode="bilinear", align_corners=False)
        evidence = evidence.to(device=feat.device, dtype=feat.dtype)
        stats = stats.to(device=feat.device, dtype=feat.dtype)

        z = self.norm(feat)
        priors = self._token_priors(evidence)
        prior_stats = priors.mean(dim=(2, 3))
        evidence_stats = evidence.mean(dim=(2, 3))
        tokens = self.token_seed.to(device=feat.device, dtype=feat.dtype).unsqueeze(0).expand(feat.shape[0], -1, -1)
        token_delta = self.token_context(torch.cat([stats, evidence_stats, prior_stats], dim=1))
        tokens = tokens + 0.24 * torch.tanh(token_delta.view(feat.shape[0], self.num_tokens, self.token_dim))

        key = self.key(z)
        value = self.value(z)
        q_tok = self._to_heads(self.token_q(tokens))
        k_sp = self._to_heads(key)
        v_sp = self._to_heads(value)
        prior_log = priors.clamp_min(1.0e-4).flatten(2).log().unsqueeze(1)
        logits = torch.matmul(q_tok, k_sp.transpose(-1, -2)) / math.sqrt(float(self.head_dim))
        token_ctx = torch.matmul(torch.softmax(logits + 1.15 * prior_log, dim=-1), v_sp)
        tokens = tokens + 0.36 * self.token_proj(self._from_heads(token_ctx))

        q_sp = k_sp
        k_tok = self._to_heads(self.token_k(tokens))
        v_tok = self._to_heads(self.token_v(tokens))
        local_prior = priors.flatten(2).transpose(1, 2).clamp_min(1.0e-4).log().unsqueeze(1)
        spatial_logits = torch.matmul(q_sp, k_tok.transpose(-1, -2)) / math.sqrt(float(self.head_dim))
        spatial_ctx = torch.matmul(torch.softmax(spatial_logits + 0.85 * local_prior, dim=-1), v_tok)
        token_path = self.spatial_proj(self._from_heads(spatial_ctx, height=height, width=width))

        contact = priors[:, 0:1]
        film = priors[:, 1:2]
        rough = torch.maximum(priors[:, 2:3], priors[:, 6:7])
        if self.target_family == "concrete":
            material_detail = priors[:, 4:5]
            nuisance = torch.maximum(priors[:, 7:8], priors[:, 3:4])
        else:
            material_detail = torch.maximum(priors[:, 3:4], priors[:, 4:5])
            nuisance = priors[:, 7:8]
        support = (0.32 * contact + 0.22 * film + 0.24 * rough + 0.22 * material_detail).clamp(0.0, 1.0)
        support = support * (1.0 - 0.70 * nuisance).clamp(0.08, 1.0)
        learned_gate = torch.sigmoid(self.local_gate(torch.cat([z, priors], dim=1)))
        if self.strict_support:
            support = (support * (0.72 + 0.28 * learned_gate)).clamp(0.0, 1.0)
        else:
            support = (0.65 * support + 0.35 * learned_gate).clamp(0.0, 1.0)

        delta = self.update(torch.cat([z, token_path], dim=1)) * support
        if self.max_update_ratio > 0.0:
            delta_norm = delta.flatten(1).norm(dim=1).view(-1, 1, 1, 1).clamp_min(1e-6)
            feat_norm = feat.detach().flatten(1).norm(dim=1).view(-1, 1, 1, 1).clamp_min(1e-6)
            delta = delta * torch.minimum(torch.ones_like(delta_norm), self.max_update_ratio * feat_norm / delta_norm)
        return feat + self.scale * delta


class ConvNeXtContactRegionTokenBackbone(ConvNeXtGateCalibratedTensorCouplingBackbone):
    """S76-compatible anchor with contact-evidence token feedback."""

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        token_layers: tuple[int, ...] = (1, 3),
        token_scale: float = 0.030,
        token_max_update_ratio: float = 0.012,
        target_family: str = "all",
        strict_support: bool = False,
    ) -> None:
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=(0,),
            scale=0.0010,
            max_update_ratio=0.00055,
            artifact_suppression=0.78,
            h_temperature=10.0,
            h_margin=0.016,
            gate_temperature=6.5,
            analytic_prior_weight=0.78,
            state_gate_scale=0.35,
            stats_gate_scale=0.25,
            mechanism_floor=0.040,
            counterfactual_strength=0.12,
            active_cells=(10, 11, 16, 17),
            up_init_std=2.0e-5,
        )
        stage_channels = {0: 96, 1: 96, 3: 192}
        self.contact_region_token_conditioners = nn.ModuleDict(
            {
                str(idx): _ContactRegionTokenConditioner(
                    stage_channels[idx],
                    token_dim=96 if stage_channels[idx] <= 96 else 128,
                    hidden_dim=128 if stage_channels[idx] <= 96 else 192,
                    scale=token_scale,
                    max_update_ratio=token_max_update_ratio,
                    artifact_suppression=0.72,
                    target_family=target_family,
                    strict_support=strict_support,
                )
                for idx in token_layers
                if idx in stage_channels
            }
        )
        if not self.contact_region_token_conditioners:
            raise ValueError("ConvNeXtContactRegionTokenBackbone needs at least one valid token layer.")

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        feat = x
        for idx, layer in enumerate(self.features):
            feat = layer(feat)
            key = str(idx)
            if key in self.gate_calibrated_tensor_coupling_banks:
                feat = self.gate_calibrated_tensor_coupling_banks[key](feat, evidence, stats)
            if key in self.contact_region_token_conditioners:
                feat = self.contact_region_token_conditioners[key](feat, evidence, stats)
        self.last_feature_map = feat
        feat = self.avgpool(feat).flatten(1)
        return self.proj(feat)


class _StageFactorTokenConditioner(nn.Module):
    """RSCD factor-token conditioner inserted inside ConvNeXt stages.

    This block is deliberately earlier than the S105 readout route. It builds
    friction/material/roughness/coupling queries from PhysicsTexture evidence,
    lets them read local stage features, and writes back only in concrete
    film/hidden-roughness transition regions. The goal is to separate the
    non-additive wet/water + concrete + slight/severe mechanisms before global
    pooling, while protecting smooth wet-film and marking-dominated patches.
    """

    def __init__(
        self,
        channels: int,
        *,
        token_dim: int = 64,
        hidden_dim: int | None = None,
        rank_dim: int | None = None,
        pooled_size: int = 6,
        scale: float = 0.018,
        max_update_ratio: float = 0.0055,
        artifact_suppression: float = 0.78,
        init_std: float = 8.0e-6,
        target_mode: str = "concrete_transition",
    ) -> None:
        super().__init__()
        channels = int(channels)
        token_dim = int(token_dim)
        hidden_dim = int(hidden_dim or max(96, min(192, channels)))
        rank_dim = int(rank_dim or max(32, min(80, channels // 2)))
        if target_mode not in {"concrete_transition", "dry_concrete"}:
            raise ValueError(f"Unsupported stage factor-token target mode: {target_mode}")
        self.channels = channels
        self.token_dim = token_dim
        self.num_queries = 7
        self.pooled_size = int(pooled_size)
        self.scale = float(scale)
        self.max_update_ratio = max(float(max_update_ratio), 0.0)
        self.artifact_suppression = min(max(float(artifact_suppression), 0.0), 0.95)
        self.target_mode = target_mode

        self.norm = nn.GroupNorm(math.gcd(8, channels), channels)
        self.feature_proj = nn.Sequential(
            nn.Conv2d(channels, token_dim, kernel_size=1, bias=False),
            nn.GroupNorm(math.gcd(8, token_dim), token_dim),
            nn.GELU(),
        )
        self.evidence_proj = nn.Sequential(
            nn.Conv2d(14, token_dim, kernel_size=1, bias=False),
            nn.GroupNorm(math.gcd(8, token_dim), token_dim),
            nn.GELU(),
        )
        self.query_base = nn.Parameter(torch.empty(self.num_queries, token_dim))
        self.stats_to_query = nn.Sequential(
            nn.LayerNorm(28),
            nn.Linear(28, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, self.num_queries * token_dim),
        )
        self.key = nn.Linear(token_dim, token_dim)
        self.value = nn.Linear(token_dim, token_dim)
        self.token_router = nn.Sequential(
            nn.LayerNorm(self.num_queries * token_dim + 28),
            nn.Linear(self.num_queries * token_dim + 28, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, 4 + 2 * channels),
        )

        self.micro_dw = nn.Conv2d(channels, channels, kernel_size=3, padding=1, groups=channels, bias=False)
        self.meso_dw = nn.Conv2d(channels, channels, kernel_size=5, padding=2, groups=channels, bias=False)
        self.rough_dw = nn.Conv2d(channels, channels, kernel_size=3, padding=2, dilation=2, groups=channels, bias=False)
        self.film_dw = nn.Conv2d(channels, channels, kernel_size=7, padding=3, groups=channels, bias=False)
        self.low_rank = nn.Sequential(
            nn.Conv2d(channels, rank_dim, kernel_size=1, bias=False),
            nn.GELU(),
            nn.Conv2d(rank_dim, channels, kernel_size=1),
        )
        self.local_support = nn.Sequential(
            nn.Conv2d(channels + 8, hidden_dim, kernel_size=1, bias=False),
            nn.GELU(),
            nn.Conv2d(hidden_dim, 1, kernel_size=1),
        )
        self.local_state_affine = nn.Sequential(
            nn.Conv2d(8, hidden_dim, kernel_size=1, bias=False),
            nn.GELU(),
            nn.Conv2d(hidden_dim, 2 * channels, kernel_size=1),
        )

        nn.init.trunc_normal_(self.query_base, std=0.02)
        for module in (self.stats_to_query[-1], self.token_router[-1], self.local_support[-1], self.local_state_affine[-1]):
            if isinstance(module, (nn.Linear, nn.Conv2d)):
                nn.init.zeros_(module.weight)
                nn.init.zeros_(module.bias)
        last = self.low_rank[-1]
        if isinstance(last, nn.Conv2d):
            nn.init.trunc_normal_(last.weight, std=float(init_std))
            nn.init.zeros_(last.bias)

    @staticmethod
    def _clamp01(x: torch.Tensor) -> torch.Tensor:
        return x.clamp(0.0, 1.0)

    def _states_and_support(self, evidence: torch.Tensor, stats: torch.Tensor) -> tuple[torch.Tensor, torch.Tensor, torch.Tensor]:
        grad = evidence[:, 0:1].clamp(0.0, 1.5)
        lap = evidence[:, 1:2].clamp(0.0, 1.5)
        contrast = evidence[:, 2:3].clamp(0.0, 1.5)
        meso = evidence[:, 4:5].clamp(0.0, 1.5)
        macro = evidence[:, 5:6].clamp(0.0, 1.5)
        concrete = self._clamp01(evidence[:, 6:7])
        asphalt = self._clamp01(evidence[:, 7:8])
        specular = self._clamp01(evidence[:, 8:9])
        dark_water = self._clamp01(evidence[:, 9:10])
        erasure = self._clamp01(evidence[:, 10:11])
        visible_rough = self._clamp01(evidence[:, 11:12])
        winter_or_boundary = self._clamp01(evidence[:, 12:13])
        marking = self._clamp01(evidence[:, 13:14])

        wet_film = torch.maximum(specular, erasure)
        water_film = torch.maximum(dark_water, erasure)
        film = torch.maximum(wet_film, water_film).clamp(0.0, 1.0)
        rough = (
            0.30 * visible_rough
            + 0.18 * grad
            + 0.24 * lap
            + 0.14 * contrast
            + 0.07 * meso
            + 0.07 * macro
        ).clamp(0.0, 1.0)
        smooth = torch.sigmoid((0.23 - rough) * 11.0)
        slight = torch.sigmoid((rough - 0.18) * 11.0) * torch.sigmoid((0.55 - rough) * 11.0)
        severe = torch.sigmoid((rough - 0.45) * 11.0)
        concrete_margin = torch.sigmoid((concrete - asphalt) * 8.0)
        anti_mark = (1.0 - self.artifact_suppression * marking).clamp(0.12, 1.0)
        anti_winter_smooth = (1.0 - 0.42 * winter_or_boundary * smooth).clamp(0.12, 1.0)

        hidden_rough = (film * torch.maximum(slight, severe)).clamp(0.0, 1.0)
        dry_texture = ((1.0 - 0.55 * film) * rough).clamp(0.0, 1.0)
        if self.target_mode == "dry_concrete":
            film_guard = (1.0 - 0.78 * film).clamp(0.08, 1.0)
            rough_boundary = torch.maximum(slight, severe).clamp(0.0, 1.0)
            transition = (dry_texture * rough_boundary).clamp(0.0, 1.0)
            support = concrete * concrete_margin * film_guard * (0.14 + 0.86 * transition) * anti_mark
            support = (support * anti_winter_smooth).clamp(0.0, 1.0)
        else:
            transition = torch.maximum(hidden_rough, dry_texture).clamp(0.0, 1.0)
            smooth_wet_guard = (1.0 - 0.62 * film * smooth).clamp(0.16, 1.0)
            support = concrete * concrete_margin * (0.18 + 0.82 * transition) * anti_mark * anti_winter_smooth
            support = (support * smooth_wet_guard).clamp(0.0, 1.0)

        states = torch.cat(
            [
                wet_film,
                water_film,
                concrete * concrete_margin,
                smooth,
                slight,
                severe,
                transition,
                anti_mark,
            ],
            dim=1,
        )
        stats = stats.to(device=evidence.device, dtype=evidence.dtype)
        stats_concrete = stats[:, 6:7].clamp(0.0, 1.0)
        stats_asphalt = stats[:, 7:8].clamp(0.0, 1.0)
        stats_film = torch.maximum(
            torch.maximum(stats[:, 8:9].clamp(0.0, 1.0), stats[:, 9:10].clamp(0.0, 1.0)),
            stats[:, 10:11].clamp(0.0, 1.0),
        )
        stats_rough = (
            0.30 * stats[:, 11:12].clamp(0.0, 1.0)
            + 0.18 * stats[:, 0:1].clamp(0.0, 1.0)
            + 0.24 * stats[:, 1:2].clamp(0.0, 1.0)
            + 0.14 * stats[:, 2:3].clamp(0.0, 1.0)
            + 0.07 * stats[:, 4:5].clamp(0.0, 1.0)
            + 0.07 * stats[:, 5:6].clamp(0.0, 1.0)
        )
        if self.target_mode == "dry_concrete":
            stats_film_guard = (1.0 - 0.78 * stats_film).clamp(0.08, 1.0)
            stats_transition = stats_rough * torch.sigmoid((stats_rough - 0.18) * 11.0)
            stats_support = (
                stats_concrete
                * torch.sigmoid((stats_concrete - stats_asphalt) * 8.0)
                * stats_film_guard
                * (0.14 + 0.86 * stats_transition)
            ).view(-1, 1, 1, 1)
        else:
            stats_transition = torch.maximum(stats_film * torch.sigmoid((stats_rough - 0.18) * 11.0), stats_rough)
            stats_support = (
                stats_concrete
                * torch.sigmoid((stats_concrete - stats_asphalt) * 8.0)
                * (0.18 + 0.82 * stats_transition)
            ).view(-1, 1, 1, 1)
        support = (0.78 * support + 0.22 * stats_support).clamp(0.0, 1.0)
        if self.target_mode == "dry_concrete":
            route_prior = torch.cat(
                [
                    smooth * (1.0 - film),
                    slight * (1.0 - film),
                    severe * (1.0 - film),
                    dry_texture,
                ],
                dim=1,
            )
        else:
            route_prior = torch.cat(
                [
                    smooth,
                    slight,
                    severe,
                    film * (0.45 + 0.55 * torch.maximum(slight, severe)),
                ],
                dim=1,
            )
        return states, support, route_prior

    def forward(self, feat: torch.Tensor, evidence: torch.Tensor, stats: torch.Tensor) -> torch.Tensor:
        evidence = F.interpolate(evidence, size=feat.shape[-2:], mode="bilinear", align_corners=False)
        evidence = evidence.to(device=feat.device, dtype=feat.dtype)
        stats = stats.to(device=feat.device, dtype=feat.dtype)
        states, support, route_prior = self._states_and_support(evidence, stats)

        z = self.norm(feat)
        token_map = self.feature_proj(z) + self.evidence_proj(evidence)
        if token_map.shape[-2:] != (self.pooled_size, self.pooled_size):
            token_map = F.adaptive_avg_pool2d(token_map, (self.pooled_size, self.pooled_size))
        tokens = token_map.flatten(2).transpose(1, 2)
        keys = self.key(tokens)
        values = self.value(tokens)
        query = self.query_base.to(device=feat.device, dtype=feat.dtype).unsqueeze(0)
        query = query + self.stats_to_query(stats).view(stats.shape[0], self.num_queries, self.token_dim)
        attn = torch.softmax(torch.matmul(query, keys.transpose(1, 2)) / math.sqrt(float(self.token_dim)), dim=-1)
        context = torch.matmul(attn, values).flatten(1)
        routed = self.token_router(torch.cat([context, stats], dim=1))
        route_logits, affine = routed[:, :4], routed[:, 4:]
        route_prior_global = route_prior.mean(dim=(2, 3))
        route = torch.softmax(route_logits + 1.35 * route_prior_global, dim=1)

        low3 = F.avg_pool2d(z, kernel_size=3, stride=1, padding=1)
        low7 = F.avg_pool2d(z, kernel_size=7, stride=1, padding=3)
        low15 = F.avg_pool2d(z, kernel_size=15, stride=1, padding=7)
        micro = z - low3
        meso = low3 - low7
        macro = low7 - low15
        film_smooth = low15 - 0.18 * micro
        branches = torch.stack(
            [
                self.micro_dw(0.70 * micro + 0.30 * meso),
                self.meso_dw(0.30 * micro + 0.70 * meso),
                self.rough_dw(0.38 * micro + 0.62 * macro),
                self.film_dw(0.62 * film_smooth + 0.38 * macro),
            ],
            dim=1,
        )
        mixed = (branches * route.view(route.shape[0], 4, 1, 1, 1)).sum(dim=1)
        learned_support = torch.sigmoid(self.local_support(torch.cat([z, states], dim=1)))
        support = (support * (0.82 + 0.18 * learned_support)).clamp(0.0, 1.0)
        gamma_token, beta_token = affine.view(feat.shape[0], 2 * self.channels, 1, 1).chunk(2, dim=1)
        gamma_local, beta_local = self.local_state_affine(states).chunk(2, dim=1)
        delta = self.low_rank(mixed)
        delta = delta + 0.045 * torch.tanh(gamma_token + gamma_local) * z
        delta = delta + 0.045 * torch.tanh(beta_token + beta_local)
        delta = support * delta
        if self.max_update_ratio > 0.0:
            delta_norm = delta.flatten(1).norm(dim=1).view(-1, 1, 1, 1).clamp_min(1e-6)
            feat_norm = feat.detach().flatten(1).norm(dim=1).view(-1, 1, 1, 1).clamp_min(1e-6)
            delta = delta * torch.minimum(torch.ones_like(delta_norm), self.max_update_ratio * feat_norm / delta_norm)
        return feat + self.scale * delta


class ConvNeXtStageFactorTokenConditionedBackbone(ConvNeXtGateCalibratedTensorCouplingBackbone):
    """S96-compatible ConvNeXt with stage-internal RSCD factor-token conditioning."""

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        adapter_blocks: tuple[tuple[int, int], ...] = ((1, 0), (1, 1), (1, 2), (3, 0), (3, 1), (3, 2)),
        adapter_scale: float = 0.018,
        adapter_max_update_ratio: float = 0.0055,
        token_dim: int = 64,
        target_mode: str = "concrete_transition",
    ) -> None:
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=(0,),
            scale=0.0010,
            max_update_ratio=0.00055,
            artifact_suppression=0.78,
            h_temperature=10.0,
            h_margin=0.016,
            gate_temperature=6.5,
            analytic_prior_weight=0.78,
            state_gate_scale=0.35,
            stats_gate_scale=0.25,
            mechanism_floor=0.040,
            counterfactual_strength=0.12,
            active_cells=(10, 11, 16, 17),
            up_init_std=2.0e-5,
        )
        stage_channels = {1: 96, 3: 192}
        self.stage_factor_token_conditioners = nn.ModuleDict()
        for stage_idx, block_idx in adapter_blocks:
            if stage_idx not in stage_channels:
                continue
            key = f"{int(stage_idx)}_{int(block_idx)}"
            self.stage_factor_token_conditioners[key] = _StageFactorTokenConditioner(
                stage_channels[stage_idx],
                token_dim=token_dim,
                scale=adapter_scale,
                max_update_ratio=adapter_max_update_ratio,
                target_mode=target_mode,
            )
        if not self.stage_factor_token_conditioners:
            raise ValueError("ConvNeXtStageFactorTokenConditionedBackbone needs at least one valid adapter block.")

    def _run_stage_with_factor_tokens(
        self,
        stage_idx: int,
        layer: nn.Module,
        feat: torch.Tensor,
        evidence: torch.Tensor,
        stats: torch.Tensor,
    ) -> torch.Tensor:
        if not isinstance(layer, nn.Sequential):
            return layer(feat)
        for block_idx, block in enumerate(layer):
            feat = block(feat)
            key = f"{int(stage_idx)}_{int(block_idx)}"
            if key in self.stage_factor_token_conditioners:
                feat = self.stage_factor_token_conditioners[key](feat, evidence, stats)
        return feat

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        feat = x
        for idx, layer in enumerate(self.features):
            if idx in {1, 3}:
                feat = self._run_stage_with_factor_tokens(idx, layer, feat, evidence, stats)
            else:
                feat = layer(feat)
            key = str(idx)
            if key in self.gate_calibrated_tensor_coupling_banks:
                feat = self.gate_calibrated_tensor_coupling_banks[key](feat, evidence, stats)
        self.last_feature_map = feat
        feat = self.avgpool(feat).flatten(1)
        return self.proj(feat)


class _ContactKernelBlockAdapter(nn.Module):
    """RSCD contact-token gated kernel adapter inserted inside ConvNeXt stages.

    S87/S88 showed that contact tokens have useful concrete signals but are too
    late when applied after an entire stage. This adapter moves the mechanism
    inside the stage: after each ConvNeXt block, RSCD contact priors select a
    small family of depthwise kernels and a low-rank channel update. The
    original ConvNeXt block remains frozen/loadable; only this task-specific
    contact mechanism learns.
    """

    def __init__(
        self,
        channels: int,
        *,
        hidden_dim: int | None = None,
        rank_dim: int | None = None,
        scale: float = 0.022,
        max_update_ratio: float = 0.008,
        artifact_suppression: float = 0.72,
        target_family: str = "all",
        strict_support: bool = False,
        zero_init: bool = False,
    ) -> None:
        super().__init__()
        channels = int(channels)
        hidden_dim = int(hidden_dim or max(48, min(144, channels)))
        rank_dim = int(rank_dim or max(32, min(96, channels // 2)))
        if target_family not in {"all", "asphalt", "concrete", "concrete_film", "concrete_rough"}:
            raise ValueError(f"Unsupported contact-kernel target family: {target_family}")
        self.channels = channels
        self.num_tokens = 8
        self.scale = float(scale)
        self.max_update_ratio = max(float(max_update_ratio), 0.0)
        self.artifact_suppression = min(max(float(artifact_suppression), 0.0), 0.95)
        self.target_family = target_family
        self.strict_support = bool(strict_support)

        self.norm = nn.GroupNorm(math.gcd(8, channels), channels)
        self.clean_dw = nn.Conv2d(channels, channels, kernel_size=3, padding=1, groups=channels, bias=False)
        self.film_dw = nn.Conv2d(channels, channels, kernel_size=7, padding=3, groups=channels, bias=False)
        self.rough_dw = nn.Conv2d(channels, channels, kernel_size=3, padding=2, dilation=2, groups=channels, bias=False)
        self.material_dw = nn.Conv2d(channels, channels, kernel_size=5, padding=2, groups=channels, bias=False)
        self.route = nn.Sequential(
            nn.LayerNorm(28 + self.num_tokens),
            nn.Linear(28 + self.num_tokens, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, 4),
        )
        self.low_rank = nn.Sequential(
            nn.Conv2d(channels, rank_dim, kernel_size=1, bias=False),
            nn.GELU(),
            nn.Conv2d(rank_dim, channels, kernel_size=1),
        )
        self.channel_affine = nn.Sequential(
            nn.LayerNorm(28 + self.num_tokens),
            nn.Linear(28 + self.num_tokens, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, 2 * channels),
        )
        self.local_gate = nn.Sequential(
            nn.Conv2d(channels + self.num_tokens, hidden_dim, kernel_size=1, bias=False),
            nn.GELU(),
            nn.Conv2d(hidden_dim, 1, kernel_size=1),
        )
        for module in (self.route[-1], self.channel_affine[-1], self.local_gate[-1]):
            if isinstance(module, (nn.Linear, nn.Conv2d)):
                nn.init.zeros_(module.weight)
                nn.init.zeros_(module.bias)
        last = self.low_rank[-1]
        if isinstance(last, nn.Conv2d):
            if zero_init:
                nn.init.zeros_(last.weight)
            else:
                nn.init.trunc_normal_(last.weight, std=1.0e-5)
            nn.init.zeros_(last.bias)

    @staticmethod
    def _clamp01(x: torch.Tensor) -> torch.Tensor:
        return x.clamp(0.0, 1.0)

    def _token_priors(self, evidence: torch.Tensor) -> torch.Tensor:
        grad = evidence[:, 0:1].clamp(0.0, 1.5)
        lap = evidence[:, 1:2].clamp(0.0, 1.5)
        contrast = evidence[:, 2:3].clamp(0.0, 1.5)
        meso = evidence[:, 4:5].clamp(0.0, 1.5)
        macro = evidence[:, 5:6].clamp(0.0, 1.5)
        concrete = self._clamp01(evidence[:, 6:7])
        asphalt = self._clamp01(evidence[:, 7:8])
        specular = self._clamp01(evidence[:, 8:9])
        dark_water = self._clamp01(evidence[:, 9:10])
        erasure = self._clamp01(evidence[:, 10:11])
        visible_rough = self._clamp01(evidence[:, 11:12])
        boundary_or_winter = self._clamp01(evidence[:, 12:13])
        marking = self._clamp01(evidence[:, 13:14])

        material = torch.maximum(concrete, asphalt)
        film = torch.maximum(torch.maximum(specular, dark_water), erasure)
        anti_mark = (1.0 - self.artifact_suppression * marking).clamp(0.12, 1.0)
        anti_nuisance = (1.0 - 0.35 * boundary_or_winter).clamp(0.18, 1.0)
        rough = (0.32 * visible_rough + 0.20 * grad + 0.22 * lap + 0.12 * contrast + 0.06 * meso + 0.08 * macro).clamp(0.0, 1.0)
        severe = torch.sigmoid((rough - 0.42) * 10.0)
        smooth = torch.sigmoid((0.24 - rough) * 10.0)

        clean_contact = (material * anti_mark * anti_nuisance * (1.0 - 0.18 * film)).clamp(0.0, 1.0)
        film_contact = (material * film * anti_mark).clamp(0.0, 1.0)
        rough_contact = (material * rough * anti_mark * anti_nuisance).clamp(0.0, 1.0)
        asphalt_texture = (asphalt * (0.38 * grad + 0.26 * contrast + 0.24 * visible_rough + 0.12 * meso) * anti_mark).clamp(0.0, 1.0)
        concrete_break = (concrete * (0.34 * lap + 0.22 * visible_rough + 0.18 * grad + 0.16 * macro + 0.10 * meso) * anti_mark).clamp(0.0, 1.0)
        smooth_wet = (material * film * smooth * anti_mark).clamp(0.0, 1.0)
        severe_rough = (material * severe * anti_mark * anti_nuisance).clamp(0.0, 1.0)
        nuisance = torch.maximum(marking, boundary_or_winter).clamp(0.0, 1.0)
        return torch.cat(
            [
                clean_contact,
                film_contact,
                rough_contact,
                asphalt_texture,
                concrete_break,
                smooth_wet,
                severe_rough,
                nuisance,
            ],
            dim=1,
        )

    def forward(self, feat: torch.Tensor, evidence: torch.Tensor, stats: torch.Tensor) -> torch.Tensor:
        height, width = feat.shape[-2:]
        evidence = F.interpolate(evidence, size=(height, width), mode="bilinear", align_corners=False)
        evidence = evidence.to(device=feat.device, dtype=feat.dtype)
        stats = stats.to(device=feat.device, dtype=feat.dtype)
        priors = self._token_priors(evidence)
        prior_stats = priors.mean(dim=(2, 3))
        global_state = torch.cat([stats, prior_stats], dim=1)
        concrete = self._clamp01(evidence[:, 6:7])
        asphalt = self._clamp01(evidence[:, 7:8])
        if self.target_family in {"concrete", "concrete_film"}:
            family = concrete
            competitor = asphalt
            material_detail = priors[:, 4:5]
        elif self.target_family == "concrete_rough":
            family = concrete
            competitor = asphalt
            material_detail = torch.maximum(priors[:, 4:5], priors[:, 6:7])
        elif self.target_family == "asphalt":
            family = asphalt
            competitor = concrete
            material_detail = priors[:, 3:4]
        else:
            family = torch.maximum(concrete, asphalt)
            competitor = torch.zeros_like(family)
            material_detail = torch.maximum(priors[:, 3:4], priors[:, 4:5])

        z = self.norm(feat)
        low3 = F.avg_pool2d(z, kernel_size=3, stride=1, padding=1)
        low7 = F.avg_pool2d(z, kernel_size=7, stride=1, padding=3)
        micro = z - low3
        meso = low3 - low7
        film_smooth = low7 - 0.12 * micro

        branches = torch.stack(
            [
                self.clean_dw(0.70 * z + 0.30 * low3),
                self.film_dw(film_smooth),
                self.rough_dw(0.55 * micro + 0.45 * meso),
                self.material_dw(0.45 * micro + 0.55 * z),
            ],
            dim=1,
        )
        route_prior = torch.cat(
            [
                priors[:, 0:1].mean(dim=(2, 3)),
                torch.maximum(priors[:, 1:2], priors[:, 5:6]).mean(dim=(2, 3)),
                torch.maximum(priors[:, 2:3], priors[:, 6:7]).mean(dim=(2, 3)),
                material_detail.mean(dim=(2, 3)),
            ],
            dim=1,
        )
        route = torch.softmax(self.route(global_state) + 1.25 * route_prior, dim=1)
        mixed = (branches * route.view(route.shape[0], 4, 1, 1, 1)).sum(dim=1)

        contact = priors[:, 0:1]
        film = torch.maximum(priors[:, 1:2], priors[:, 5:6])
        rough = torch.maximum(priors[:, 2:3], priors[:, 6:7])
        nuisance = torch.maximum(priors[:, 7:8], 0.45 * competitor)
        if self.target_family == "concrete_film":
            support = (0.18 * contact + 0.34 * film + 0.24 * rough + 0.24 * material_detail).clamp(0.0, 1.0)
        elif self.target_family == "concrete_rough":
            support = (0.12 * contact + 0.10 * film + 0.44 * rough + 0.34 * material_detail).clamp(0.0, 1.0)
        else:
            support = (0.28 * contact + 0.22 * film + 0.25 * rough + 0.25 * material_detail).clamp(0.0, 1.0)
        if self.target_family != "all":
            if self.target_family == "concrete_film":
                support = support * family * (0.34 + 0.66 * film).clamp(0.0, 1.0)
            elif self.target_family == "concrete_rough":
                rough_floor = (0.25 + 0.75 * rough).clamp(0.0, 1.0)
                wet_smooth_suppress = (1.0 - 0.58 * priors[:, 5:6]).clamp(0.18, 1.0)
                support = support * family * rough_floor * wet_smooth_suppress
            else:
                support = support * family
            support = support * (1.0 - 0.62 * competitor).clamp(0.06, 1.0)
        support = support * (1.0 - 0.70 * nuisance).clamp(0.10, 1.0)
        learned_gate = torch.sigmoid(self.local_gate(torch.cat([z, priors], dim=1)))
        if self.strict_support:
            support = (support * (0.76 + 0.24 * learned_gate)).clamp(0.0, 1.0)
        else:
            support = (0.75 * support + 0.25 * learned_gate).clamp(0.0, 1.0)

        gamma, beta = self.channel_affine(global_state).view(feat.shape[0], -1, 1, 1).chunk(2, dim=1)
        delta = self.low_rank(mixed) + 0.035 * torch.tanh(gamma) * z + 0.035 * torch.tanh(beta)
        delta = support * delta
        if self.max_update_ratio > 0.0:
            delta_norm = delta.flatten(1).norm(dim=1).view(-1, 1, 1, 1).clamp_min(1e-6)
            feat_norm = feat.detach().flatten(1).norm(dim=1).view(-1, 1, 1, 1).clamp_min(1e-6)
            delta = delta * torch.minimum(torch.ones_like(delta_norm), self.max_update_ratio * feat_norm / delta_norm)
        return feat + self.scale * delta


class ConvNeXtContactKernelModulatedBackbone(ConvNeXtGateCalibratedTensorCouplingBackbone):
    """S76-compatible ConvNeXt with contact-kernel adapters inside stages."""

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        adapter_blocks: tuple[tuple[int, int], ...] = ((1, 0), (1, 1), (1, 2), (3, 0), (3, 1), (3, 2)),
        adapter_scale: float = 0.022,
        adapter_max_update_ratio: float = 0.008,
    ) -> None:
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=(0,),
            scale=0.0010,
            max_update_ratio=0.00055,
            artifact_suppression=0.78,
            h_temperature=10.0,
            h_margin=0.016,
            gate_temperature=6.5,
            analytic_prior_weight=0.78,
            state_gate_scale=0.35,
            stats_gate_scale=0.25,
            mechanism_floor=0.040,
            counterfactual_strength=0.12,
            active_cells=(10, 11, 16, 17),
            up_init_std=2.0e-5,
        )
        stage_channels = {1: 96, 3: 192}
        self.contact_kernel_block_adapters = nn.ModuleDict()
        for stage_idx, block_idx in adapter_blocks:
            if stage_idx not in stage_channels:
                continue
            key = f"{int(stage_idx)}_{int(block_idx)}"
            self.contact_kernel_block_adapters[key] = _ContactKernelBlockAdapter(
                stage_channels[stage_idx],
                scale=adapter_scale,
                max_update_ratio=adapter_max_update_ratio,
                artifact_suppression=0.72,
            )
        if not self.contact_kernel_block_adapters:
            raise ValueError("ConvNeXtContactKernelModulatedBackbone needs at least one adapter block.")

    def _run_stage_with_adapters(
        self,
        stage_idx: int,
        layer: nn.Module,
        feat: torch.Tensor,
        evidence: torch.Tensor,
        stats: torch.Tensor,
    ) -> torch.Tensor:
        if not isinstance(layer, nn.Sequential):
            return layer(feat)
        for block_idx, block in enumerate(layer):
            feat = block(feat)
            key = f"{int(stage_idx)}_{int(block_idx)}"
            if key in self.contact_kernel_block_adapters:
                feat = self.contact_kernel_block_adapters[key](feat, evidence, stats)
        return feat

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        feat = x
        for idx, layer in enumerate(self.features):
            if idx in {1, 3}:
                feat = self._run_stage_with_adapters(idx, layer, feat, evidence, stats)
            else:
                feat = layer(feat)
            key = str(idx)
            if key in self.gate_calibrated_tensor_coupling_banks:
                feat = self.gate_calibrated_tensor_coupling_banks[key](feat, evidence, stats)
        self.last_feature_map = feat
        feat = self.avgpool(feat).flatten(1)
        return self.proj(feat)


class ConvNeXtFamilyContactKernelModulatedBackbone(ConvNeXtGateCalibratedTensorCouplingBackbone):
    """S76-compatible stage-internal contact kernels with material-separated charts.

    S89 proved that stage-internal contact kernels can move the difficult
    slight/severe boundaries, but one shared adapter leaked corrections across
    asphalt and concrete. S90 uses two zero-start adapter banks: an asphalt
    chart and a concrete chart. Their gates are tied to PhysicsTexture material
    evidence, so each bank learns a different coupling form instead of one
    pooled operator for all paved classes.
    """

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        adapter_blocks: tuple[tuple[int, int], ...] = ((1, 0), (1, 1), (1, 2), (3, 0), (3, 1), (3, 2)),
        asphalt_scale: float = 0.014,
        concrete_scale: float = 0.018,
        adapter_max_update_ratio: float = 0.006,
        use_asphalt_adapter: bool = True,
        use_concrete_adapter: bool = True,
        concrete_target_family: str = "concrete",
    ) -> None:
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=(0,),
            scale=0.0010,
            max_update_ratio=0.00055,
            artifact_suppression=0.78,
            h_temperature=10.0,
            h_margin=0.016,
            gate_temperature=6.5,
            analytic_prior_weight=0.78,
            state_gate_scale=0.35,
            stats_gate_scale=0.25,
            mechanism_floor=0.040,
            counterfactual_strength=0.12,
            active_cells=(10, 11, 16, 17),
            up_init_std=2.0e-5,
        )
        stage_channels = {1: 96, 3: 192}
        self.asphalt_contact_kernel_block_adapters = nn.ModuleDict()
        self.concrete_contact_kernel_block_adapters = nn.ModuleDict()
        for stage_idx, block_idx in adapter_blocks:
            if stage_idx not in stage_channels:
                continue
            key = f"{int(stage_idx)}_{int(block_idx)}"
            channels = stage_channels[stage_idx]
            if use_asphalt_adapter:
                self.asphalt_contact_kernel_block_adapters[key] = _ContactKernelBlockAdapter(
                    channels,
                    scale=asphalt_scale,
                    max_update_ratio=adapter_max_update_ratio,
                    artifact_suppression=0.74,
                    target_family="asphalt",
                    strict_support=True,
                    zero_init=True,
                )
            if use_concrete_adapter:
                self.concrete_contact_kernel_block_adapters[key] = _ContactKernelBlockAdapter(
                    channels,
                    scale=concrete_scale,
                    max_update_ratio=adapter_max_update_ratio,
                    artifact_suppression=0.74,
                    target_family=concrete_target_family,
                    strict_support=True,
                    zero_init=True,
                )
        if not self.asphalt_contact_kernel_block_adapters and not self.concrete_contact_kernel_block_adapters:
            raise ValueError("ConvNeXtFamilyContactKernelModulatedBackbone needs at least one adapter block.")

    def _run_stage_with_adapters(
        self,
        stage_idx: int,
        layer: nn.Module,
        feat: torch.Tensor,
        evidence: torch.Tensor,
        stats: torch.Tensor,
    ) -> torch.Tensor:
        if not isinstance(layer, nn.Sequential):
            return layer(feat)
        for block_idx, block in enumerate(layer):
            feat = block(feat)
            key = f"{int(stage_idx)}_{int(block_idx)}"
            if key in self.asphalt_contact_kernel_block_adapters:
                feat = self.asphalt_contact_kernel_block_adapters[key](feat, evidence, stats)
            if key in self.concrete_contact_kernel_block_adapters:
                feat = self.concrete_contact_kernel_block_adapters[key](feat, evidence, stats)
        return feat

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        feat = x
        for idx, layer in enumerate(self.features):
            if idx in {1, 3}:
                feat = self._run_stage_with_adapters(idx, layer, feat, evidence, stats)
            else:
                feat = layer(feat)
            key = str(idx)
            if key in self.gate_calibrated_tensor_coupling_banks:
                feat = self.gate_calibrated_tensor_coupling_banks[key](feat, evidence, stats)
        self.last_feature_map = feat
        feat = self.avgpool(feat).flatten(1)
        return self.proj(feat)


class _WaterConcreteDifferentialBlockAdapter(nn.Module):
    """Stage-internal differential adapter for wet/water concrete hard pairs.

    The audited S76/S90-S92 errors show that water-concrete slight is mainly
    confused with water-concrete severe and wet-concrete slight. This adapter
    therefore does not ask the feature map to learn a broad "contact" update.
    It constructs separate early/mid feature axes for water-vs-wet and
    slight-vs-severe, then writes only inside concrete film regions where those
    two axes are simultaneously uncertain.
    """

    def __init__(
        self,
        channels: int,
        *,
        rank_dim: int | None = None,
        hidden_dim: int | None = None,
        scale: float = 0.020,
        max_update_ratio: float = 0.006,
        artifact_suppression: float = 0.78,
        occlusion_relaxed: bool = False,
    ) -> None:
        super().__init__()
        channels = int(channels)
        rank_dim = int(rank_dim or max(32, min(72, channels // 2)))
        hidden_dim = int(hidden_dim or max(64, min(144, channels)))
        self.scale = float(scale)
        self.max_update_ratio = max(float(max_update_ratio), 0.0)
        self.artifact_suppression = min(max(float(artifact_suppression), 0.0), 0.95)
        self.occlusion_relaxed = bool(occlusion_relaxed)

        self.norm = nn.GroupNorm(math.gcd(8, channels), channels)
        self.down = nn.Conv2d(channels, rank_dim, kernel_size=1, bias=False)
        self.evidence_embed = nn.Sequential(
            nn.Conv2d(8, rank_dim, kernel_size=3, padding=1, bias=False),
            nn.GroupNorm(math.gcd(8, rank_dim), rank_dim),
            nn.GELU(),
        )
        self.water_dw = nn.Conv2d(rank_dim, rank_dim, kernel_size=7, padding=3, groups=rank_dim, bias=False)
        self.wet_dw = nn.Conv2d(rank_dim, rank_dim, kernel_size=5, padding=2, groups=rank_dim, bias=False)
        self.slight_dw = nn.Conv2d(rank_dim, rank_dim, kernel_size=3, padding=1, groups=rank_dim, bias=False)
        self.severe_dw = nn.Conv2d(rank_dim, rank_dim, kernel_size=3, padding=2, dilation=2, groups=rank_dim, bias=False)
        self.smooth_dw = nn.Conv2d(rank_dim, rank_dim, kernel_size=9, padding=4, groups=rank_dim, bias=False)
        self.diff_proj = nn.Sequential(
            nn.Conv2d(4 * rank_dim, rank_dim, kernel_size=1, bias=False),
            nn.GroupNorm(math.gcd(8, rank_dim), rank_dim),
            nn.GELU(),
            nn.Conv2d(rank_dim, rank_dim, kernel_size=1, bias=False),
        )
        self.local_router = nn.Sequential(
            nn.Conv2d(rank_dim + 8, hidden_dim, kernel_size=1, bias=False),
            nn.GELU(),
            nn.Conv2d(hidden_dim, 5, kernel_size=1),
        )
        self.stats_router = nn.Sequential(
            nn.LayerNorm(28),
            nn.Linear(28, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, 5),
        )
        self.local_support = nn.Sequential(
            nn.Conv2d(rank_dim + 8, hidden_dim, kernel_size=1, bias=False),
            nn.GELU(),
            nn.Conv2d(hidden_dim, 1, kernel_size=1),
        )
        self.up = nn.Conv2d(rank_dim, channels, kernel_size=1)
        for module in (self.local_router[-1], self.stats_router[-1], self.local_support[-1], self.up):
            if isinstance(module, (nn.Conv2d, nn.Linear)):
                nn.init.zeros_(module.weight)
                nn.init.zeros_(module.bias)

    @staticmethod
    def _clamp01(x: torch.Tensor) -> torch.Tensor:
        return x.clamp(0.0, 1.0)

    def _states(self, evidence: torch.Tensor, stats: torch.Tensor) -> tuple[torch.Tensor, torch.Tensor, torch.Tensor]:
        grad = evidence[:, 0:1].clamp(0.0, 1.5)
        lap = evidence[:, 1:2].clamp(0.0, 1.5)
        contrast = evidence[:, 2:3].clamp(0.0, 1.5)
        micro = evidence[:, 3:4].clamp(0.0, 1.5)
        meso = evidence[:, 4:5].clamp(0.0, 1.5)
        macro = evidence[:, 5:6].clamp(0.0, 1.5)
        concrete = self._clamp01(evidence[:, 6:7])
        asphalt = self._clamp01(evidence[:, 7:8])
        specular = self._clamp01(evidence[:, 8:9])
        dark_water = self._clamp01(evidence[:, 9:10])
        erasure = self._clamp01(evidence[:, 10:11])
        visible_rough = self._clamp01(evidence[:, 11:12])
        winter = self._clamp01(evidence[:, 12:13])
        marking = self._clamp01(evidence[:, 13:14])

        wet = (torch.maximum(specular, erasure) * (1.0 - 0.45 * dark_water)).clamp(0.0, 1.0)
        water = (0.74 * dark_water + 0.26 * erasure).clamp(0.0, 1.0)
        film = torch.maximum(wet, water)
        if self.occlusion_relaxed:
            hidden_rough = (
                0.24 * contrast
                + 0.20 * lap
                + 0.18 * grad
                + 0.15 * micro
                + 0.13 * meso
                + 0.10 * macro
            ).clamp(0.0, 1.0)
            rough = (0.54 * hidden_rough + 0.30 * visible_rough + 0.16 * film * (meso + macro).clamp(0.0, 1.0)).clamp(
                0.0, 1.0
            )
            smooth = torch.sigmoid((0.32 - rough) * 8.0)
            slight = torch.sigmoid((rough - 0.16) * 9.0) * torch.sigmoid((0.50 - rough) * 8.0)
            severe = torch.sigmoid((rough - 0.34) * 9.0)
            paved = torch.maximum(concrete, asphalt).clamp(0.0, 1.0)
            material_uncertain = (film * paved * torch.sigmoid((0.30 - (concrete - asphalt).abs()) * 5.0)).clamp(0.0, 1.0)
            concrete_margin = torch.maximum(concrete * torch.sigmoid((concrete - asphalt) * 7.0), 0.42 * material_uncertain)
        else:
            rough = (
                0.34 * visible_rough
                + 0.18 * grad
                + 0.16 * lap
                + 0.14 * contrast
                + 0.10 * micro
                + 0.05 * meso
                + 0.03 * macro
            ).clamp(0.0, 1.0)
            smooth = torch.sigmoid((0.28 - rough) * 11.0)
            slight = torch.sigmoid((rough - 0.20) * 12.0) * torch.sigmoid((0.56 - rough) * 10.0)
            severe = torch.sigmoid((rough - 0.45) * 12.0)
            concrete_margin = torch.sigmoid((concrete - asphalt) * 9.0)
        anti_artifact = (1.0 - self.artifact_suppression * torch.maximum(marking, winter)).clamp(0.10, 1.0)

        concrete_state = concrete * concrete_margin if not self.occlusion_relaxed else concrete_margin
        states = torch.cat([concrete_state, water, wet, film, smooth, slight, severe, anti_artifact], dim=1)
        pair_priors = torch.cat(
            [
                concrete_state * water * slight,
                concrete_state * water * severe,
                concrete_state * wet * slight,
                concrete_state * wet * severe,
                concrete_state * film * smooth * (0.25 + 0.75 * slight),
            ],
            dim=1,
        )
        pair_priors = pair_priors * anti_artifact
        stats = stats.to(device=evidence.device, dtype=evidence.dtype)
        concrete_stats = stats[:, 6:7].clamp(0.0, 1.0)
        asphalt_stats = stats[:, 7:8].clamp(0.0, 1.0)
        film_stats = torch.maximum(torch.maximum(stats[:, 8:9], stats[:, 9:10]), stats[:, 10:11]).clamp(0.0, 1.0)
        if self.occlusion_relaxed:
            paved_stats = torch.maximum(concrete_stats, asphalt_stats)
            uncertain_stats = film_stats * paved_stats * torch.sigmoid((0.30 - (concrete_stats - asphalt_stats).abs()) * 5.0)
            concrete_stats = torch.maximum(
                concrete_stats * torch.sigmoid((concrete_stats - asphalt_stats) * 7.0),
                0.42 * uncertain_stats,
            )
        else:
            concrete_stats = concrete_stats * torch.sigmoid((concrete_stats - asphalt_stats) * 9.0)
        global_support = (concrete_stats * (0.25 + 0.75 * film_stats)).view(-1, 1, 1, 1)
        local_support = pair_priors.sum(dim=1, keepdim=True).clamp(0.0, 1.0)
        support = (0.70 * local_support + 0.30 * global_support).clamp(0.0, 1.0)
        return states, pair_priors, support

    def forward(self, feat: torch.Tensor, evidence: torch.Tensor, stats: torch.Tensor) -> torch.Tensor:
        evidence = F.interpolate(evidence, size=feat.shape[-2:], mode="bilinear", align_corners=False)
        evidence = evidence.to(device=feat.device, dtype=feat.dtype)
        stats = stats.to(device=feat.device, dtype=feat.dtype)
        states, pair_priors, support = self._states(evidence, stats)

        z = self.down(self.norm(feat)) + 0.28 * self.evidence_embed(states)
        low3 = F.avg_pool2d(z, kernel_size=3, stride=1, padding=1)
        low7 = F.avg_pool2d(z, kernel_size=7, stride=1, padding=3)
        low15 = F.avg_pool2d(z, kernel_size=15, stride=1, padding=7)
        micro = z - low3
        meso = low3 - low7
        macro = low7 - low15
        smooth_base = low15

        water_axis = self.water_dw(0.18 * micro + 0.30 * meso + 0.52 * smooth_base)
        wet_axis = self.wet_dw(0.10 * micro + 0.36 * meso + 0.54 * smooth_base)
        slight_axis = self.slight_dw(0.22 * micro + 0.58 * meso + 0.20 * macro)
        severe_axis = self.severe_dw(0.38 * micro + 0.22 * meso + 0.40 * macro)
        smooth_axis = self.smooth_dw(smooth_base - 0.14 * micro)

        water_slight = water_axis + slight_axis - 0.34 * severe_axis - 0.12 * wet_axis
        water_severe = water_axis + severe_axis - 0.24 * slight_axis
        wet_slight = wet_axis + slight_axis - 0.18 * water_axis
        wet_severe = wet_axis + severe_axis - 0.18 * slight_axis
        smooth_bridge = smooth_axis - 0.20 * slight_axis + 0.10 * wet_axis

        contrast = self.diff_proj(
            torch.cat(
                [
                    water_slight - water_severe,
                    wet_slight - wet_severe,
                    water_slight - wet_slight,
                    smooth_bridge - 0.50 * (water_slight + wet_slight),
                ],
                dim=1,
            )
        )
        route_logits = self.local_router(torch.cat([z, states], dim=1)) + self.stats_router(stats).view(
            feat.shape[0], 5, 1, 1
        )
        learned_route = torch.softmax(route_logits, dim=1)
        prior_route = pair_priors / pair_priors.sum(dim=1, keepdim=True).clamp_min(1e-4)
        route = 0.38 * learned_route + 0.62 * prior_route
        mixed = (
            route[:, 0:1] * water_slight
            + route[:, 1:2] * water_severe
            + route[:, 2:3] * wet_slight
            + route[:, 3:4] * wet_severe
            + route[:, 4:5] * smooth_bridge
            + 0.22 * contrast
        )
        learned_support = torch.sigmoid(self.local_support(torch.cat([z, states], dim=1)))
        support = (support * (0.76 + 0.24 * learned_support)).clamp(0.0, 1.0)
        delta = self.up(F.gelu(mixed)) * support
        if self.max_update_ratio > 0.0:
            delta_norm = delta.flatten(1).norm(dim=1).view(-1, 1, 1, 1).clamp_min(1e-6)
            feat_norm = feat.detach().flatten(1).norm(dim=1).view(-1, 1, 1, 1).clamp_min(1e-6)
            delta = delta * torch.minimum(torch.ones_like(delta_norm), self.max_update_ratio * feat_norm / delta_norm)
        return feat + self.scale * delta


class ConvNeXtWaterConcreteDifferentialBackbone(ConvNeXtGateCalibratedTensorCouplingBackbone):
    """S76-compatible ConvNeXt with wet/water-concrete differential adapters."""

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        adapter_blocks: tuple[tuple[int, int], ...] = ((1, 0), (1, 1), (1, 2), (3, 0), (3, 1), (3, 2)),
        adapter_scale: float = 0.020,
        adapter_max_update_ratio: float = 0.006,
        occlusion_relaxed: bool = False,
    ) -> None:
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=(0,),
            scale=0.0010,
            max_update_ratio=0.00055,
            artifact_suppression=0.78,
            h_temperature=10.0,
            h_margin=0.016,
            gate_temperature=6.5,
            analytic_prior_weight=0.78,
            state_gate_scale=0.35,
            stats_gate_scale=0.25,
            mechanism_floor=0.040,
            counterfactual_strength=0.12,
            active_cells=(10, 11, 16, 17),
            up_init_std=2.0e-5,
        )
        stage_channels = {1: 96, 3: 192}
        self.water_concrete_differential_adapters = nn.ModuleDict()
        for stage_idx, block_idx in adapter_blocks:
            if stage_idx not in stage_channels:
                continue
            key = f"{int(stage_idx)}_{int(block_idx)}"
            self.water_concrete_differential_adapters[key] = _WaterConcreteDifferentialBlockAdapter(
                stage_channels[stage_idx],
                scale=adapter_scale,
                max_update_ratio=adapter_max_update_ratio,
                artifact_suppression=0.78,
                occlusion_relaxed=occlusion_relaxed,
            )
        if not self.water_concrete_differential_adapters:
            raise ValueError("ConvNeXtWaterConcreteDifferentialBackbone needs at least one adapter block.")

    def _run_stage_with_adapters(
        self,
        stage_idx: int,
        layer: nn.Module,
        feat: torch.Tensor,
        evidence: torch.Tensor,
        stats: torch.Tensor,
    ) -> torch.Tensor:
        if not isinstance(layer, nn.Sequential):
            return layer(feat)
        for block_idx, block in enumerate(layer):
            feat = block(feat)
            key = f"{int(stage_idx)}_{int(block_idx)}"
            if key in self.water_concrete_differential_adapters:
                feat = self.water_concrete_differential_adapters[key](feat, evidence, stats)
        return feat

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        feat = x
        for idx, layer in enumerate(self.features):
            if idx in {1, 3}:
                feat = self._run_stage_with_adapters(idx, layer, feat, evidence, stats)
            else:
                feat = layer(feat)
            key = str(idx)
            if key in self.gate_calibrated_tensor_coupling_banks:
                feat = self.gate_calibrated_tensor_coupling_banks[key](feat, evidence, stats)
        self.last_feature_map = feat
        feat = self.avgpool(feat).flatten(1)
        return self.proj(feat)


class ConvNeXtConcreteFilmOrdinalProjectedBackbone(ConvNeXtGateCalibratedTensorCouplingBackbone):
    """Concrete-film ordinal route with a gated backbone projection reader.

    S69 showed that the ordinal route can help several concrete classes only
    when the backbone projection is allowed to move, but a global projection
    update leaks into asphalt severe/slight classes. This variant keeps the
    same early wet/water-concrete ordinal tensor cells and adds a zero-start
    projection adapter whose gate is high only when concrete, film, and
    roughness evidence are jointly present.
    """

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        adapter_hidden_dim: int | None = None,
        adapter_scale: float = 0.075,
        adapter_max_update_ratio: float = 0.030,
        adapter_gate_temperature: float = 7.0,
        adapter_gate_floor: float = 0.0,
        condition_layers: tuple[int, ...] = (0,),
        scale: float = 0.0021,
        max_update_ratio: float = 0.00125,
        artifact_suppression: float = 0.80,
        h_temperature: float = 9.8,
        h_margin: float = 0.013,
        gate_temperature: float = 6.0,
        analytic_prior_weight: float = 0.76,
        state_gate_scale: float = 0.38,
        stats_gate_scale: float = 0.26,
        mechanism_floor: float = 0.050,
        counterfactual_strength: float = 0.16,
        up_init_std: float = 2.4e-5,
    ) -> None:
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=condition_layers,
            scale=scale,
            max_update_ratio=max_update_ratio,
            artifact_suppression=artifact_suppression,
            h_temperature=h_temperature,
            h_margin=h_margin,
            active_cells=(9, 10, 11, 15, 16, 17),
            gate_temperature=gate_temperature,
            analytic_prior_weight=analytic_prior_weight,
            state_gate_scale=state_gate_scale,
            stats_gate_scale=stats_gate_scale,
            mechanism_floor=mechanism_floor,
            counterfactual_strength=counterfactual_strength,
            up_init_std=up_init_std,
        )
        hidden_dim = int(adapter_hidden_dim or max(96, min(256, out_dim // 3)))
        self.ordinal_projection_adapter_scale = float(adapter_scale)
        self.ordinal_projection_adapter_max_update_ratio = max(float(adapter_max_update_ratio), 0.0)
        self.ordinal_projection_adapter_gate_temperature = max(float(adapter_gate_temperature), 1e-3)
        self.ordinal_projection_adapter_gate_floor = min(max(float(adapter_gate_floor), 0.0), 0.20)
        self.ordinal_projection_adapter = nn.Sequential(
            nn.LayerNorm(out_dim + 28),
            nn.Linear(out_dim + 28, hidden_dim),
            nn.GELU(),
            nn.Linear(hidden_dim, out_dim),
        )
        last = self.ordinal_projection_adapter[-1]
        if isinstance(last, nn.Linear):
            nn.init.zeros_(last.weight)
            nn.init.zeros_(last.bias)

    def _projection_gate(self, stats: torch.Tensor, dtype: torch.dtype) -> torch.Tensor:
        stats = stats.float()
        concrete = stats[:, 6:7].clamp(0.0, 1.0)
        asphalt = stats[:, 7:8].clamp(0.0, 1.0)
        specular = stats[:, 8:9].clamp(0.0, 1.0)
        dark_water = stats[:, 9:10].clamp(0.0, 1.0)
        erasure = stats[:, 10:11].clamp(0.0, 1.0)
        visible_rough = stats[:, 11:12].clamp(0.0, 1.0)
        marking = stats[:, 13:14].clamp(0.0, 1.0)
        film = torch.maximum(specular, torch.maximum(dark_water, erasure)).clamp(0.0, 1.0)
        rough_gate = (0.45 * visible_rough + 0.30 * stats[:, 4:5].clamp(0.0, 1.0) + 0.25 * stats[:, 5:6].clamp(0.0, 1.0)).clamp(0.0, 1.0)
        concrete_margin = torch.sigmoid((concrete - asphalt) * self.ordinal_projection_adapter_gate_temperature)
        support = concrete * concrete_margin * (0.35 + 0.65 * film) * (0.35 + 0.65 * rough_gate)
        support = support * (1.0 - 0.70 * marking).clamp(0.20, 1.0)
        if self.ordinal_projection_adapter_gate_floor > 0.0:
            support = self.ordinal_projection_adapter_gate_floor + (1.0 - self.ordinal_projection_adapter_gate_floor) * support
        return support.to(dtype=dtype)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        feat = x
        for idx, layer in enumerate(self.features):
            feat = layer(feat)
            key = str(idx)
            if key in self.gate_calibrated_tensor_coupling_banks:
                feat = self.gate_calibrated_tensor_coupling_banks[key](feat, evidence, stats)
        self.last_feature_map = feat
        feat = self.avgpool(feat).flatten(1)
        projected = self.proj(feat)
        adapter_in = torch.cat([projected, stats.to(device=projected.device, dtype=projected.dtype)], dim=1)
        delta = self.ordinal_projection_adapter(adapter_in)
        gate = self._projection_gate(stats, projected.dtype).to(device=projected.device)
        delta = gate * delta
        if self.ordinal_projection_adapter_max_update_ratio > 0.0:
            delta_norm = delta.norm(dim=1, keepdim=True).clamp_min(1e-6)
            base_norm = projected.detach().norm(dim=1, keepdim=True).clamp_min(1e-6)
            limit = self.ordinal_projection_adapter_max_update_ratio * base_norm
            delta = delta * torch.minimum(torch.ones_like(delta_norm), limit / delta_norm)
        return projected + self.ordinal_projection_adapter_scale * delta


class ConvNeXtFamilySafeTensorCouplingBackbone(ConvNeXtGateCalibratedTensorCouplingBackbone):
    """Gate-calibrated tensor coupling with family-separated no-harm routes.

    The current best model uses an early tensor route only for wet/water
    concrete slight/severe cells. Follow-up screens showed that repairs for
    asphalt or dry-concrete cells can regress water-concrete classes when they
    share one late update. This backbone keeps the validated route and adds
    zero-initialized, physically separated early routes for dry concrete,
    asphalt film severity, and wet/water concrete smooth bridges. Each route
    has its own cell mask and norm bound, so training a weak family has a much
    smaller channel through which it can overwrite another family.
    """

    def __init__(
        self,
        out_dim: int,
        pretrained: bool = False,
        *,
        condition_layers: tuple[int, ...] = (0,),
        scale: float = 0.0010,
        max_update_ratio: float = 0.00055,
        artifact_suppression: float = 0.78,
        h_temperature: float = 10.0,
        h_margin: float = 0.016,
        gate_temperature: float = 6.5,
        analytic_prior_weight: float = 0.78,
        state_gate_scale: float = 0.35,
        stats_gate_scale: float = 0.25,
        mechanism_floor: float = 0.040,
        counterfactual_strength: float = 0.12,
        extra_route_scale_mult: float = 1.0,
        extra_max_update_mult: float = 1.0,
        extra_route_up_init_std: float = 0.0,
        use_family_route_router: bool = False,
        family_route_router_hidden_dim: int | None = None,
        family_route_router_temperature: float = 1.0,
        family_route_router_protect_bias: float = 1.2,
        family_route_router_active_bias: float = -1.2,
        family_route_min_prob: float = 0.0,
        family_route_use_analytic_support: bool = False,
        family_route_support_floor: float = 0.0,
        family_route_support_power: float = 1.0,
        split_concrete_film_routes: bool = False,
        shape_topology_evidence: bool = False,
        opponent_retinex_evidence: bool = False,
        precision_observer_evidence: bool = False,
        morphology_scale_evidence: bool = False,
        spectral_scattering_evidence: bool = False,
        enabled_extra_routes: tuple[str, ...] | None = None,
    ) -> None:
        evidence_channels = 14 + (4 if bool(shape_topology_evidence) else 0) + (
            4 if bool(opponent_retinex_evidence) else 0
        ) + (
            4 if bool(precision_observer_evidence) else 0
        ) + (
            4 if bool(morphology_scale_evidence) else 0
        ) + (
            4 if bool(spectral_scattering_evidence) else 0
        )
        stats_dim = 2 * evidence_channels
        super().__init__(
            out_dim,
            pretrained=pretrained,
            condition_layers=condition_layers,
            scale=scale,
            max_update_ratio=max_update_ratio,
            artifact_suppression=artifact_suppression,
            h_temperature=h_temperature,
            h_margin=h_margin,
            active_cells=(10, 11, 16, 17),
            evidence_channels=evidence_channels,
            stats_dim=stats_dim,
            gate_temperature=gate_temperature,
            analytic_prior_weight=analytic_prior_weight,
            state_gate_scale=state_gate_scale,
            stats_gate_scale=stats_gate_scale,
            mechanism_floor=mechanism_floor,
            counterfactual_strength=counterfactual_strength,
            up_init_std=2.0e-5,
        )
        stage_channels = {0: 96, 1: 96, 3: 192}
        extra_route_scale_mult = max(float(extra_route_scale_mult), 0.0)
        extra_max_update_mult = max(float(extra_max_update_mult), 0.0)
        extra_route_up_init_std = max(float(extra_route_up_init_std), 0.0)
        self.shape_topology_evidence = bool(shape_topology_evidence)
        self.opponent_retinex_evidence = bool(opponent_retinex_evidence)
        self.precision_observer_evidence = bool(precision_observer_evidence)
        self.morphology_scale_evidence = bool(morphology_scale_evidence)
        self.spectral_scattering_evidence = bool(spectral_scattering_evidence)
        self.family_route_stats_dim = int(stats_dim)
        self.split_concrete_film_routes = bool(split_concrete_film_routes)
        valid_route_names = (
            "dry_concrete",
            "asphalt_film",
            "concrete_smooth_bridge",
            "concrete_hidden_slight",
            "concrete_hidden_severe",
        )
        if enabled_extra_routes is None:
            enabled_route_set: set[str] | None = None
        else:
            enabled_route_set = {str(name) for name in enabled_extra_routes}
            invalid_routes = sorted(enabled_route_set.difference(valid_route_names))
            if invalid_routes:
                raise ValueError(f"invalid enabled family-safe routes: {invalid_routes}")
            if not enabled_route_set:
                raise ValueError("enabled_extra_routes must contain at least one route when provided")
        self.enabled_extra_routes = tuple(sorted(enabled_route_set)) if enabled_route_set is not None else None
        if self.split_concrete_film_routes:
            # Split the old wet/water-concrete route into physically different
            # coupling forms: smooth film bridge, hidden slight roughness, and
            # hidden severe roughness. This is a task-specific early mechanism
            # split, not a late classifier head.
            self.family_route_names = (
                "protect",
                "dry_concrete",
                "asphalt_film",
                "concrete_smooth_bridge",
                "concrete_hidden_slight",
                "concrete_hidden_severe",
            )
        else:
            self.family_route_names = ("protect", "dry_concrete", "asphalt_film", "concrete_smooth_bridge")
        if enabled_route_set is not None:
            self.family_route_names = ("protect",) + tuple(name for name in self.family_route_names if name in enabled_route_set)
        self.family_route_router_temperature = max(float(family_route_router_temperature), 1e-3)
        self.family_route_min_prob = min(max(float(family_route_min_prob), 0.0), 0.20)
        self.family_route_use_analytic_support = bool(family_route_use_analytic_support)
        self.family_route_support_floor = min(max(float(family_route_support_floor), 0.0), 0.50)
        self.family_route_support_power = max(float(family_route_support_power), 1e-3)
        self.family_safe_tensor_coupling_banks = nn.ModuleDict()
        self.family_route_routers = nn.ModuleDict()
        for idx in condition_layers:
            if idx not in stage_channels:
                continue
            channels = stage_channels[idx]
            route_banks = {
                    "dry_concrete": _GateCalibratedTensorCouplingBank(
                        channels,
                        evidence_channels=evidence_channels,
                        stats_dim=stats_dim,
                        scale=0.00062 * extra_route_scale_mult,
                        max_update_ratio=0.00032 * extra_max_update_mult,
                        artifact_suppression=0.82,
                        h_temperature=10.5,
                        h_margin=0.018,
                        active_cells=(4, 5),
                        gate_temperature=6.0,
                        analytic_prior_weight=0.82,
                        state_gate_scale=0.24,
                        stats_gate_scale=0.18,
                        mechanism_floor=0.035,
                        counterfactual_strength=0.10,
                        up_init_std=extra_route_up_init_std,
                    ),
                    "asphalt_film": _GateCalibratedTensorCouplingBank(
                        channels,
                        evidence_channels=evidence_channels,
                        stats_dim=stats_dim,
                        scale=0.00058 * extra_route_scale_mult,
                        max_update_ratio=0.00030 * extra_max_update_mult,
                        artifact_suppression=0.84,
                        h_temperature=10.5,
                        h_margin=0.018,
                        active_cells=(7, 8, 13, 14),
                        gate_temperature=6.0,
                        analytic_prior_weight=0.80,
                        state_gate_scale=0.22,
                        stats_gate_scale=0.18,
                        mechanism_floor=0.035,
                        counterfactual_strength=0.10,
                        up_init_std=extra_route_up_init_std,
                    ),
                    "concrete_smooth_bridge": _GateCalibratedTensorCouplingBank(
                        channels,
                        evidence_channels=evidence_channels,
                        stats_dim=stats_dim,
                        scale=0.00042 * extra_route_scale_mult,
                        max_update_ratio=0.00022 * extra_max_update_mult,
                        artifact_suppression=0.86,
                        h_temperature=11.0,
                        h_margin=0.020,
                        active_cells=(9, 15),
                        gate_temperature=6.5,
                        analytic_prior_weight=0.84,
                        state_gate_scale=0.18,
                        stats_gate_scale=0.14,
                        mechanism_floor=0.030,
                        counterfactual_strength=0.08,
                        up_init_std=extra_route_up_init_std,
                    ),
                }
            if self.split_concrete_film_routes:
                route_banks.update(
                    {
                        "concrete_hidden_slight": _GateCalibratedTensorCouplingBank(
                            channels,
                            evidence_channels=evidence_channels,
                            stats_dim=stats_dim,
                            scale=0.00050 * extra_route_scale_mult,
                            max_update_ratio=0.00026 * extra_max_update_mult,
                            artifact_suppression=0.84,
                            h_temperature=10.8,
                            h_margin=0.018,
                            active_cells=(10, 16),
                            gate_temperature=6.5,
                            analytic_prior_weight=0.84,
                            state_gate_scale=0.20,
                            stats_gate_scale=0.16,
                            mechanism_floor=0.032,
                            counterfactual_strength=0.10,
                            up_init_std=extra_route_up_init_std,
                        ),
                        "concrete_hidden_severe": _GateCalibratedTensorCouplingBank(
                            channels,
                            evidence_channels=evidence_channels,
                            stats_dim=stats_dim,
                            scale=0.00052 * extra_route_scale_mult,
                            max_update_ratio=0.00028 * extra_max_update_mult,
                            artifact_suppression=0.82,
                            h_temperature=10.2,
                            h_margin=0.014,
                            active_cells=(11, 17),
                            gate_temperature=6.0,
                            analytic_prior_weight=0.80,
                            state_gate_scale=0.22,
                            stats_gate_scale=0.18,
                            mechanism_floor=0.035,
                            counterfactual_strength=0.12,
                            up_init_std=extra_route_up_init_std,
                        ),
                    }
                )
            if enabled_route_set is not None:
                route_banks = {name: bank for name, bank in route_banks.items() if name in enabled_route_set}
                if not route_banks:
                    raise ValueError("enabled_extra_routes removed all family-safe tensor banks")
            self.family_safe_tensor_coupling_banks[str(idx)] = nn.ModuleDict(route_banks)
            if bool(use_family_route_router):
                hidden_dim = int(family_route_router_hidden_dim or max(48, min(160, channels)))
                router = nn.Sequential(
                    nn.LayerNorm(2 * channels + self.family_route_stats_dim),
                    nn.Linear(2 * channels + self.family_route_stats_dim, hidden_dim),
                    nn.GELU(),
                    nn.Linear(hidden_dim, len(self.family_route_names)),
                )
                last = router[-1]
                if isinstance(last, nn.Linear):
                    nn.init.zeros_(last.weight)
                    nn.init.constant_(last.bias, float(family_route_router_active_bias))
                    with torch.no_grad():
                        last.bias[0] = float(family_route_router_protect_bias)
                self.family_route_routers[str(idx)] = router
        if not self.family_safe_tensor_coupling_banks:
            raise ValueError("ConvNeXtFamilySafeTensorCouplingBackbone requires a valid condition layer.")
        self.last_family_route_logits: dict[str, torch.Tensor] = {}
        self.last_family_route_probs: dict[str, torch.Tensor] = {}
        self.last_family_route_effective_probs: dict[str, torch.Tensor] = {}

    def _boundary_evidence(self, x: torch.Tensor) -> tuple[torch.Tensor, torch.Tensor]:
        base_evidence, base_stats = super()._boundary_evidence(x)
        if (
            not self.shape_topology_evidence
            and not self.opponent_retinex_evidence
            and not self.precision_observer_evidence
            and not self.morphology_scale_evidence
            and not self.spectral_scattering_evidence
        ):
            return base_evidence, base_stats

        mean = self.mean.to(device=x.device, dtype=x.dtype)
        std = self.std.to(device=x.device, dtype=x.dtype)
        rgb = (x * std + mean).clamp(0.0, 1.0)
        gray = 0.299 * rgb[:, 0:1] + 0.587 * rgb[:, 1:2] + 0.114 * rgb[:, 2:3]
        sobel_x = self.sobel_x.to(device=x.device, dtype=gray.dtype)
        sobel_y = self.sobel_y.to(device=x.device, dtype=gray.dtype)
        gx = F.conv2d(gray, sobel_x, padding=1)
        gy = F.conv2d(gray, sobel_y, padding=1)
        jxx = F.avg_pool2d(gx.square(), kernel_size=7, stride=1, padding=3)
        jyy = F.avg_pool2d(gy.square(), kernel_size=7, stride=1, padding=3)
        jxy = F.avg_pool2d(gx * gy, kernel_size=7, stride=1, padding=3)
        trace = (jxx + jyy).clamp_min(1e-5)
        orientation_coherence = torch.sqrt((jxx - jyy).square() + 4.0 * jxy.square() + 1e-6) / trace

        grad = base_evidence[:, 0:1].clamp(0.0, 1.5)
        lap = base_evidence[:, 1:2].clamp(0.0, 1.5)
        contrast = base_evidence[:, 2:3].clamp(0.0, 1.5)
        micro = base_evidence[:, 3:4].clamp(0.0, 1.5)
        value = rgb.max(dim=1, keepdim=True).values
        saturation = (value - rgb.min(dim=1, keepdim=True).values) / value.clamp_min(1e-4)
        concrete_like = base_evidence[:, 6:7].clamp(0.0, 1.0)
        asphalt_like = base_evidence[:, 7:8].clamp(0.0, 1.0)
        specular = base_evidence[:, 8:9].clamp(0.0, 1.0)
        dark_water = base_evidence[:, 9:10].clamp(0.0, 1.0)
        film_erasure = base_evidence[:, 10:11].clamp(0.0, 1.0)
        visible_roughness = base_evidence[:, 11:12].clamp(0.0, 1.0)
        marking = base_evidence[:, 13:14].clamp(0.0, 1.0)
        extras: list[torch.Tensor] = []

        rough_density = F.avg_pool2d(visible_roughness, kernel_size=7, stride=1, padding=3)
        film = torch.maximum(torch.maximum(specular, film_erasure), 0.72 * dark_water).clamp(0.0, 1.0)
        anti_marking = (1.0 - 0.55 * marking).clamp(0.20, 1.0)

        if self.shape_topology_evidence:
            line_structure = orientation_coherence.clamp(0.0, 1.0) * torch.sigmoid((grad - 0.040) * 28.0)
            rough_connectivity = visible_roughness * torch.sigmoid((rough_density - 0.22) * 10.0)
            film_rough_interface = film * torch.clamp(
                0.38 * rough_density + 0.26 * lap + 0.22 * contrast + 0.14 * micro,
                0.0,
                1.0,
            )
            isotropic_microtexture = rough_density * (1.0 - 0.62 * line_structure).clamp(0.0, 1.0)
            extras.append(
                torch.cat(
                    [
                        line_structure,
                        rough_connectivity * anti_marking,
                        film_rough_interface * anti_marking,
                        isotropic_microtexture * anti_marking,
                    ],
                    dim=1,
                )
            )

        retinex_texture = contrast
        opponent_chroma = saturation
        neutral_sheen = specular
        dark_neutral_pool = dark_water
        if self.opponent_retinex_evidence:
            red_green = (rgb[:, 0:1] - rgb[:, 1:2]).abs()
            blue_yellow = (rgb[:, 2:3] - 0.5 * (rgb[:, 0:1] + rgb[:, 1:2])).abs()
            opponent_chroma = torch.sqrt(red_green.square() + blue_yellow.square() + 1e-6).clamp(0.0, 1.0)
            log_luma = torch.log(gray.clamp_min(1e-4))
            retinex = (log_luma - F.avg_pool2d(log_luma, kernel_size=21, stride=1, padding=10)).abs()
            retinex_texture = torch.sigmoid((retinex - 0.055) * 18.0) * anti_marking
            neutral_sheen = specular * torch.sigmoid((0.18 - opponent_chroma) * 18.0)
            dark_neutral_pool = dark_water * torch.sigmoid((0.20 - opponent_chroma) * 16.0)
            opponent_edge = F.avg_pool2d(opponent_chroma, kernel_size=5, stride=1, padding=2) * torch.sigmoid(
                (grad + contrast - 0.085) * 18.0
            )
            extras.append(
                torch.cat(
                    [
                        retinex_texture,
                        neutral_sheen * anti_marking,
                        dark_neutral_pool * anti_marking,
                        opponent_edge * anti_marking,
                    ],
                    dim=1,
                )
            )

        if self.precision_observer_evidence:
            material_sum = (concrete_like + asphalt_like).clamp_min(1e-4)
            material_margin = (concrete_like - asphalt_like).abs() / material_sum
            material_precision = torch.sigmoid((material_margin - 0.18) * 9.0) * anti_marking
            film_strength = torch.maximum(torch.maximum(specular, film_erasure), torch.maximum(neutral_sheen, dark_neutral_pool))
            film_precision = torch.sigmoid((film_strength - 0.18) * 9.0) * torch.sigmoid((0.38 - opponent_chroma) * 8.0)
            rough_precision = torch.clamp(
                0.38 * rough_density + 0.24 * visible_roughness + 0.20 * retinex_texture + 0.18 * contrast,
                0.0,
                1.0,
            ) * anti_marking
            exposure_high = torch.sigmoid((value - 0.88) * 18.0)
            exposure_low = torch.sigmoid((0.16 - value) * 18.0)
            material_ambiguity = (1.0 - material_margin).clamp(0.0, 1.0)
            nuisance_uncertainty = torch.clamp(
                0.34 * marking + 0.24 * exposure_high + 0.18 * exposure_low + 0.24 * material_ambiguity,
                0.0,
                1.0,
            )
            extras.append(
                torch.cat(
                    [
                        material_precision,
                        film_precision * anti_marking,
                        rough_precision,
                        nuisance_uncertainty,
                    ],
                    dim=1,
                )
            )

        if self.morphology_scale_evidence:
            erode5 = -F.max_pool2d(-gray, kernel_size=5, stride=1, padding=2)
            dilate5 = F.max_pool2d(gray, kernel_size=5, stride=1, padding=2)
            open5 = F.max_pool2d(erode5, kernel_size=5, stride=1, padding=2)
            close5 = -F.max_pool2d(-dilate5, kernel_size=5, stride=1, padding=2)
            erode13 = -F.max_pool2d(-gray, kernel_size=13, stride=1, padding=6)
            dilate13 = F.max_pool2d(gray, kernel_size=13, stride=1, padding=6)
            open13 = F.max_pool2d(erode13, kernel_size=13, stride=1, padding=6)
            close13 = -F.max_pool2d(-dilate13, kernel_size=13, stride=1, padding=6)
            bright_granules = (gray - open5).relu()
            dark_pits = (close5 - gray).relu()
            meso_granules = (open5 - open13).abs() + (close13 - close5).abs()
            scale_balance = (bright_granules + dark_pits) / (
                meso_granules + bright_granules + dark_pits + 1e-4
            )
            morphology_gate = anti_marking * (1.0 - 0.35 * film).clamp(0.25, 1.0)
            extras.append(
                torch.cat(
                    [
                        torch.sigmoid((bright_granules - 0.020) * 26.0) * morphology_gate,
                        torch.sigmoid((dark_pits - 0.020) * 26.0) * morphology_gate,
                        torch.sigmoid((meso_granules - 0.030) * 20.0) * anti_marking,
                        scale_balance.clamp(0.0, 1.0) * anti_marking,
                    ],
                    dim=1,
                )
            )

        if self.spectral_scattering_evidence:
            smooth5 = F.avg_pool2d(gray, kernel_size=5, stride=1, padding=2)
            smooth17 = F.avg_pool2d(gray, kernel_size=17, stride=1, padding=8)
            smooth33 = F.avg_pool2d(gray, kernel_size=33, stride=1, padding=16)
            high_band = (gray - smooth5).abs()
            mid_band = (smooth5 - smooth17).abs()
            low_band = (smooth17 - smooth33).abs()
            band_energy = 0.58 * high_band + 0.42 * mid_band
            high_freq_energy = torch.sigmoid((high_band - 0.020) * 30.0) * anti_marking
            mid_freq_energy = torch.sigmoid((mid_band - 0.018) * 28.0) * anti_marking
            low_frequency_film = (
                film
                * torch.sigmoid((0.055 - band_energy) * 26.0)
                * torch.sigmoid((low_band + 0.20 * specular + 0.18 * dark_water - 0.035) * 16.0)
                * anti_marking
            )
            spectral_suppression = (
                film
                * torch.sigmoid((0.070 - high_band - 0.65 * mid_band) * 28.0)
                * (0.55 + 0.45 * film_erasure)
                * anti_marking
            )
            extras.append(
                torch.cat(
                    [
                        high_freq_energy.clamp(0.0, 1.0),
                        mid_freq_energy.clamp(0.0, 1.0),
                        low_frequency_film.clamp(0.0, 1.0),
                        spectral_suppression.clamp(0.0, 1.0),
                    ],
                    dim=1,
                )
            )

        evidence = torch.cat([base_evidence] + [extra.clamp(0.0, 1.5) for extra in extras], dim=1)
        stats = torch.cat(
            [item.mean(dim=(2, 3)) for item in evidence.split(1, dim=1)]
            + [item.std(dim=(2, 3), unbiased=False) for item in evidence.split(1, dim=1)],
            dim=1,
        )
        return evidence, stats

    def _family_route_support(self, name: str, stats: torch.Tensor, dtype: torch.dtype) -> torch.Tensor:
        stats = stats.to(dtype=torch.float32)
        grad = stats[:, 0].clamp(0.0, 1.0)
        lap = stats[:, 1].clamp(0.0, 1.0)
        contrast = stats[:, 2].clamp(0.0, 1.0)
        micro = stats[:, 3].clamp(0.0, 1.0)
        concrete = stats[:, 6].clamp(0.0, 1.0)
        asphalt = stats[:, 7].clamp(0.0, 1.0)
        specular = stats[:, 8].clamp(0.0, 1.0)
        dark_water = stats[:, 9].clamp(0.0, 1.0)
        erasure = stats[:, 10].clamp(0.0, 1.0)
        visible_rough = stats[:, 11].clamp(0.0, 1.0)
        marking = stats[:, 13].clamp(0.0, 1.0)
        if stats.shape[1] >= 36:
            line_structure = stats[:, 14].clamp(0.0, 1.0)
            rough_connectivity = stats[:, 15].clamp(0.0, 1.0)
            film_rough_interface = stats[:, 16].clamp(0.0, 1.0)
            isotropic_microtexture = stats[:, 17].clamp(0.0, 1.0)
        else:
            line_structure = torch.zeros_like(grad)
            rough_connectivity = visible_rough
            film_rough_interface = torch.zeros_like(grad)
            isotropic_microtexture = visible_rough
        if stats.shape[1] >= 44:
            retinex_texture = stats[:, 18].clamp(0.0, 1.0)
            neutral_sheen = stats[:, 19].clamp(0.0, 1.0)
            dark_neutral_pool = stats[:, 20].clamp(0.0, 1.0)
            opponent_edge = stats[:, 21].clamp(0.0, 1.0)
        else:
            retinex_texture = contrast
            neutral_sheen = specular
            dark_neutral_pool = dark_water
            opponent_edge = contrast
        if stats.shape[1] >= 52:
            material_precision = stats[:, 22].clamp(0.0, 1.0)
            film_precision = stats[:, 23].clamp(0.0, 1.0)
            rough_precision = stats[:, 24].clamp(0.0, 1.0)
            nuisance_uncertainty = stats[:, 25].clamp(0.0, 1.0)
        else:
            material_precision = torch.ones_like(grad)
            film_precision = torch.maximum(specular, dark_water).clamp(0.0, 1.0)
            rough_precision = visible_rough
            nuisance_uncertainty = marking
        if stats.shape[1] >= 60:
            bright_granules = stats[:, 26].clamp(0.0, 1.0)
            dark_pits = stats[:, 27].clamp(0.0, 1.0)
            meso_granules = stats[:, 28].clamp(0.0, 1.0)
            scale_balance = stats[:, 29].clamp(0.0, 1.0)
        else:
            bright_granules = micro
            dark_pits = lap
            meso_granules = contrast
            scale_balance = visible_rough
        if stats.shape[1] >= 68:
            high_freq_energy = stats[:, 30].clamp(0.0, 1.0)
            mid_freq_energy = stats[:, 31].clamp(0.0, 1.0)
            low_frequency_film = stats[:, 32].clamp(0.0, 1.0)
            spectral_suppression = stats[:, 33].clamp(0.0, 1.0)
        else:
            high_freq_energy = (0.55 * lap + 0.45 * micro).clamp(0.0, 1.0)
            mid_freq_energy = contrast
            low_frequency_film = torch.maximum(specular, torch.maximum(dark_water, erasure)).clamp(0.0, 1.0)
            spectral_suppression = torch.zeros_like(grad)
        wet_film = torch.clamp(
            0.25 * dark_water
            + 0.22 * specular
            + 0.20 * erasure
            + 0.13 * neutral_sheen
            + 0.12 * dark_neutral_pool
            + 0.08 * (1.0 - contrast)
            + 0.06 * low_frequency_film
            + 0.04 * spectral_suppression,
            0.0,
            1.0,
        )
        precision_guard = (1.0 - 0.40 * nuisance_uncertainty).clamp(0.35, 1.0)
        wet_film = (wet_film * (0.72 + 0.28 * film_precision) * precision_guard).clamp(0.0, 1.0)
        rough_signal = torch.clamp(
            0.25 * visible_rough
            + 0.17 * grad
            + 0.13 * lap
            + 0.08 * contrast
            + 0.12 * rough_connectivity
            + 0.06 * isotropic_microtexture
            + 0.05 * retinex_texture
            + 0.08 * bright_granules
            + 0.06 * dark_pits
            + 0.05 * meso_granules
            + 0.05 * high_freq_energy
            + 0.05 * mid_freq_energy,
            0.0,
            1.0,
        )
        rough_signal = (rough_signal * (0.74 + 0.26 * rough_precision) * precision_guard).clamp(0.0, 1.0)
        severe_signal = torch.clamp(
            0.28 * lap
            + 0.18 * grad
            + 0.10 * contrast
            + 0.10 * visible_rough
            + 0.12 * film_rough_interface
            + 0.06 * rough_connectivity
            + 0.03 * opponent_edge
            + 0.08 * dark_pits
            + 0.05 * meso_granules
            + 0.04 * high_freq_energy
            + 0.05 * mid_freq_energy,
            0.0,
            1.0,
        )
        line_artifact_guard = (1.0 - 0.45 * line_structure * marking).clamp(0.35, 1.0)
        material_guard = (0.55 + 0.45 * material_precision).clamp(0.35, 1.0)
        if name == "asphalt_film":
            support = (
                asphalt
                * wet_film
                * (
                    0.48
                    + 0.16 * rough_signal
                    + 0.12 * film_rough_interface
                    + 0.10 * neutral_sheen
                    + 0.08 * low_frequency_film
                    + 0.06 * spectral_suppression
                )
                * (1.0 - 0.55 * concrete)
                * (1.0 - 0.50 * marking)
                * line_artifact_guard
                * material_guard
            )
        elif name == "dry_concrete":
            dry_texture = (
                (
                    0.50 * rough_signal
                    + 0.18 * rough_connectivity
                    + 0.12 * isotropic_microtexture
                    + 0.12 * meso_granules
                    + 0.08 * scale_balance
                    + 0.05 * high_freq_energy
                    + 0.05 * mid_freq_energy
                )
                * (1.0 - wet_film)
                * (1.0 - 0.40 * marking)
                * line_artifact_guard
                * material_guard
            )
            support = concrete * dry_texture
        elif name == "concrete_smooth_bridge":
            smooth_bridge = wet_film * (
                1.0
                + 0.28 * low_frequency_film
                + 0.16 * spectral_suppression
                - 0.50 * rough_signal
                - 0.24 * rough_connectivity
                - 0.09 * retinex_texture
                - 0.08 * high_freq_energy
                - 0.08 * mid_freq_energy
            ).clamp(0.0, 1.0)
            support = concrete * smooth_bridge * (1.0 - 0.45 * marking) * material_guard
        elif name == "concrete_hidden_slight":
            medium_rough = (
                wet_film
                * (
                    0.28
                    + 0.31 * rough_signal
                    + 0.17 * rough_connectivity
                    + 0.10 * film_rough_interface
                    + 0.09 * meso_granules
                    + 0.05 * scale_balance
                    + 0.06 * mid_freq_energy
                    + 0.05 * spectral_suppression
                )
                * (1.0 - 0.52 * severe_signal).clamp(0.0, 1.0)
            )
            support = concrete * medium_rough * (1.0 - 0.45 * marking) * line_artifact_guard * material_guard
        elif name == "concrete_hidden_severe":
            hidden_severe = (
                wet_film
                * (
                    0.34 * rough_signal
                    + 0.22 * film_rough_interface
                    + 0.20 * rough_connectivity
                    + 0.14 * dark_pits
                    + 0.10 * meso_granules
                    + 0.06 * high_freq_energy
                    + 0.06 * mid_freq_energy
                    + 0.04 * spectral_suppression
                )
                * (0.32 + 0.68 * severe_signal)
            )
            support = concrete * hidden_severe * (1.0 - 0.40 * marking) * material_guard
        else:
            support = torch.ones_like(asphalt)
        support = support.clamp(0.0, 1.0).pow(self.family_route_support_power)
        if self.family_route_support_floor > 0.0:
            support = self.family_route_support_floor + (1.0 - self.family_route_support_floor) * support
        return support.to(dtype=dtype)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        evidence, stats = self._boundary_evidence(x)
        feat = x
        self.last_family_route_logits = {}
        self.last_family_route_probs = {}
        self.last_family_route_effective_probs = {}
        for idx, layer in enumerate(self.features):
            feat = layer(feat)
            key = str(idx)
            if key in self.gate_calibrated_tensor_coupling_banks:
                feat = self.gate_calibrated_tensor_coupling_banks[key](feat, evidence, stats)
            if key in self.family_safe_tensor_coupling_banks:
                route_probs: torch.Tensor | None = None
                if key in self.family_route_routers:
                    pooled = torch.cat(
                        [
                            feat.mean(dim=(2, 3)),
                            feat.std(dim=(2, 3), unbiased=False),
                            stats.to(device=feat.device, dtype=feat.dtype),
                        ],
                        dim=1,
                    )
                    route_logits = self.family_route_routers[key](pooled)
                    route_probs = torch.softmax(route_logits / self.family_route_router_temperature, dim=1)
                    if self.family_route_min_prob > 0.0:
                        floor = self.family_route_min_prob / float(len(self.family_route_names))
                        route_probs = floor + (1.0 - self.family_route_min_prob) * route_probs
                    self.last_family_route_logits[key] = route_logits
                    self.last_family_route_probs[key] = route_probs
                for name, bank in self.family_safe_tensor_coupling_banks[key].items():
                    if route_probs is None:
                        feat = bank(feat, evidence, stats)
                        continue
                    route_idx = self.family_route_names.index(str(name))
                    route_weight = route_probs[:, route_idx]
                    if self.family_route_use_analytic_support:
                        route_weight = route_weight * self._family_route_support(str(name), stats, route_weight.dtype).to(
                            device=route_weight.device,
                            dtype=route_weight.dtype,
                        )
                    self.last_family_route_effective_probs[f"{key}:{name}"] = route_weight.detach()
                    before = feat
                    updated = bank(feat, evidence, stats)
                    delta = updated - before
                    feat = before + route_weight.view(-1, 1, 1, 1).to(
                        device=delta.device,
                        dtype=delta.dtype,
                    ) * delta
        self.last_feature_map = feat
        feat = self.avgpool(feat).flatten(1)
        return self.proj(feat)


class TimmConvNeXtFeatureBackbone(nn.Module):
    """timm ConvNeXt wrapper that preserves FAF spatial feature maps.

    This is a diagnostic backbone for the RSCD task: it tests whether stronger
    ImageNet-22K ConvNeXt pretraining improves the same PhysicsTexture/LPF/SPA
    surface-friction pipeline without dropping the local spatial evidence used
    by the current model.
    """

    def __init__(self, name: str, out_dim: int, pretrained: bool = False) -> None:
        super().__init__()
        import timm

        self.model = timm.create_model(name, pretrained=pretrained, num_classes=0, global_pool="avg")
        in_features = int(getattr(self.model, "num_features"))
        self.proj = nn.Linear(in_features, out_dim)
        self.out_dim = out_dim
        self.last_feature_map: torch.Tensor | None = None
        self.stage_feature_maps: dict[str, torch.Tensor] = {}

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        stage_maps: dict[str, torch.Tensor] = {}
        if hasattr(self.model, "stem") and hasattr(self.model, "stages"):
            feat = self.model.stem(x)
            stage_maps["stem"] = feat
            for idx, stage in enumerate(self.model.stages):
                feat = stage(feat)
                if idx == 0:
                    stage_maps["early"] = feat
                elif idx == 1:
                    stage_maps["mid"] = feat
                elif idx == 2:
                    stage_maps["late"] = feat
                elif idx == 3:
                    stage_maps["final"] = feat
            if hasattr(self.model, "norm_pre"):
                feat = self.model.norm_pre(feat)
        else:
            feat = self.model.forward_features(x)
            stage_maps["final"] = feat
        self.stage_feature_maps = stage_maps
        self.last_feature_map = feat
        if hasattr(self.model, "forward_head"):
            pooled = self.model.forward_head(feat, pre_logits=True)
        else:
            pooled = feat.mean(dim=(2, 3)) if feat.ndim == 4 else feat
        return self.proj(pooled)


class TimmBackbone(nn.Module):
    def __init__(self, name: str, out_dim: int, pretrained: bool = False) -> None:
        super().__init__()
        import timm

        try:
            if "dinov2" in name:
                self.model = timm.create_model(
                    name,
                    pretrained=pretrained,
                    num_classes=0,
                    global_pool="token",
                    dynamic_img_size=True,
                )
            else:
                self.model = timm.create_model(
                    name,
                    pretrained=pretrained,
                    num_classes=0,
                    global_pool="avg",
                    dynamic_img_size=True,
                )
        except TypeError:
            pool = "token" if "dinov2" in name else "avg"
            self.model = timm.create_model(name, pretrained=pretrained, num_classes=0, global_pool=pool)
        in_features = int(getattr(self.model, "num_features"))
        self.proj = nn.Linear(in_features, out_dim)
        self.out_dim = out_dim

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        feat = self.model(x)
        if feat.ndim == 4:
            if feat.shape[1] == self.proj.in_features:
                feat = feat.mean(dim=(2, 3))
            elif feat.shape[-1] == self.proj.in_features:
                feat = feat.mean(dim=(1, 2))
            else:
                feat = feat.flatten(2).mean(dim=2)
        elif feat.ndim == 3:
            if feat.shape[-1] == self.proj.in_features:
                feat = feat.mean(dim=1)
            elif feat.shape[1] == self.proj.in_features:
                feat = feat.mean(dim=2)
            else:
                feat = feat.flatten(1)
        elif feat.ndim == 2 and feat.shape[1] != self.proj.in_features:
            if feat.shape[1] % self.proj.in_features == 0:
                feat = feat.view(feat.shape[0], -1, self.proj.in_features).mean(dim=1)
        return self.proj(feat)


